const questions = [
  { cat: 4, q: "Kaj je izobata?", a: "Izobata je črta, ki povezuje točke  istih globin." },
  { cat: 6, q: "Kako naredimo in zakaj uporabljamo različne vozle ?", a: "- OSMICA - se uporablja kot zaključek na vrveh\n- MOŠKI VOZEL - za spajanje dveh vrvi, za podvezovanje jader ipd.\n- ŽENSKI VOZEL - se ne uporablja, ker drsi.\n- ZASTAVNI VOZEL - za privezovanje zastav na dvižno vrvico (od tu je dobil ime), predvsem je primeren za spajanje dveh vrvi, ko je ena od obeh vrvi tanjša, uporabimo dvojni zastavni vozel. \n- SIDRNI VOZEL - za privezovanje sidra.\n- VOZEL ZA BOJO - za privezovanje na rinko ali bojo.\n- PAŠNJAK ALI NEZATEGLJIVA ZANKA - za privez plovila na bitvo. Prednost tega vozla je v tem, da se ne zadrgne in se da z lahkoto odvezati. To prednost s pridom uporabimo kjerkoli.\n- VRZNI VOZEL - za privez bokoščitnic na ograjo čolna. Ni primeren za privezovanje, ker se zadrgne. \n- SKRAJŠEVALNI VOZEL - za hitro začasno skrajševanje zaradi poškodbe ali prevelike dolžine vrvi." },
  { cat: 2, q: "Kaj je nadvodje?", a: "Nadvodje je navpična oddaljenost na boku, merjeno od vodne črte do zgornjega roba palube (robnice)." },
  { cat: 2, q: "Zakaj in kje uporabljamo četverovez ?", a: "Uporabljamo ga zaradi ekonomičnosti, ker je potreben le del obale, kolikor je čoln širok. Uporabljamo ga v pristaniščih in marinah." },
  { cat: 2, q: "Kaj je vodna črta ?", a: "Vodna črta je črta, ki deli  plovilo na potopljeni del in na nadvodje." },
  { cat: 6, q: "Kdaj je potrebno  opraviti izredni pregled čolna ?", a: "1. Izredni pregled je obvezen: \n-\tkadar je čoln imel izreden dogodek (trčenje, potopitev, požar in podobno), \n-\tče je lastnik čolna spremenil plovbne lastnosti čolna (čoln podaljšal, skrajšal, razširil, zožil, nadgradil in podobno), \n-\tv primerih, kadar obstaja utemeljen sum, da čoln ne izpolnjuje pogojev glede sposobnosti za plovbo oziroma da stanje čolna glede konstrukcije ali plovbnih lastnosti ali opreme očitno ne ustreza veljavnim listinam. \n2. V primeru izrednega dogodka je oseba, ki upravlja čoln oziroma lastnik čolna, dolžan o tem takoj obvestiti upravo, njeno izpostavo oziroma upravno enoto, kjer je čoln vpisan, v opravičenih primerih pa najkasneje v treh dneh. \n3. V primeru, da je lastnik čolna spremenil plovbne lastnosti čolna, je dolžan o tem najkasneje v roku osmih dni obvestiti upravo, njeno izpostavo oziroma upravno enoto, kjer je čoln vpisan. \n4. Če je čoln imel izredni dogodek, obsega izredni pregled vsa opravila rednega pregleda za ugotovitev sposobnosti čolna za plovbo. V tem primeru se rok za naslednji redni pregled šteje od dneva izrednega pregleda dalje. \n5. Če je lastnik čolna spremenil plovbne lastnosti čolna ali če obstaja utemeljen sum, da čoln ne izpolnjuje pogojev glede sposobnosti za plovbo oziroma da stanje čolna glede konstrukcije ali plovbnih lastnosti ali opreme očitno ne ustreza veljavnim listinam, obsega izredni pregled opravila, s katerimi se ugotovi skladnost stanja konstrukcije ali plovbnih lastnosti ali opreme z veljavnimi listinami. V tem primeru se rok za naslednji redni pregled šteje neodvisno od izrednega pregleda." },
  { cat: 2, q: "Če se sidramo med drugimi že zasidranimi plovili, kaj moramo upoštevati ?", a: "Zasidran čoln  se pod vplivom toka in vetra obrača okoli točke sidranja. Zato moramo upoštevati radius obračanja  in  čoln zasidramo na varni razdalji od ostalih že zasidranih plovil." },
  { cat: 5, q: "Koliko se smejo oddaljiti od obale čolni na v vesla, neregistrirani čolni (čoln, ki niso vpisani v vpisnik čolnov, kot so kajak, vodno kolo, čoln na vesla, jadralec na deski ...?", a: "Navedena plovila se smejo oddaljiti do 1000 m od obale." },
  { cat: 3, q: "Kako ravnamo pri uporabi novega motorja ?", a: "Pri uporabi novega motorja se moramo ravnati po navodilih proizvajalca (priročnik motorja)." },
  { cat: 3, q: "Kaj se zgodi, če je toplotna vrednost svečke premajhna ?", a: "Pri večjih obremenitvah se pojavi samovžig zaradi žarenja svečke." },
  { cat: 5, q: "Kakšna mora biti najmanjša  dimenzija črk in številk označbe čolna ?", a: "-\tČrki in številke označbe čolna morajo imeti naslednje mere: višina 10 cm, širina 5 cm, s širino linij 1 cm ter medsebojno razdaljo 1 cm. Če so mere večje, mora biti ohranjeno predpisano razmerje. \n-\tRibiški čoln, daljši od 10 m in krajši od 17 m, mora imeti črke in številke v višini najmanj 25 cm in širini najmanj 4 cm. Ribiški čoln, daljši od 17 m, mora imeti črke in številke v višini najmanj 45 cm in širini  najmanj 6 cm. \n-\tČrke in številke morajo biti med seboj ločene s pomišljajem." },
  { cat: 2, q: "Kako se imenujejo privezne  vrvi  pri privezu čolna ob obalo ?", a: "Privezne vrvi dobijo svoje ime šele takrat, ko jih uporabimo. Privezne vrvi so: premčna vrv, krmna vrv, krmna bočna (tresin), premčna bočna (tresin), sprednja in zadnja brzda (špring)." },
  { cat: 3, q: "Kaj je vzrok, da se plovilo s krmnim motorjem ne premakne kljub temu, da motor deluje?", a: "V takem primeru pogledamo, če zatič na propelerju, ki ga drži fiksno na osovino,  ni prekinjen. V primeru, da je \nzatič prekinjen, se bo os vrtela, propeler pa praktično ne in zato ne more odrivati vodo. Zatič se prelomi \npri udarcu ob trd predmet, lahko pa tudi, če pri valovitem stanju morja krmo in s tem tudi motor vrže iz vode in \nmotor pridobi obrate, ker ni več upora vode. Ko se nato noga motorja potopi v morje, pride do \nnenadnega upora vode in s tem večje obremenitve propelerja, kar lahko povzroči prelom \nzatiča. Zato je potrebno za odpravo navedene okvare vedno imeti rezervni zatič in primerno orodje." },
  { cat: 6, q: "Kateri zvočni signal pomeni  »moji stroji delujejo nazaj«?", a: "Tri kratki piski." },
  { cat: 4, q: "Kaj je premčev kot (L)?", a: "Premčev kot je kot med linijo opazovalca in opazovanim objektom ter vzdolžnico ladje v smeri plovbe. Premčev kot se meri s pomočjo smerne plošče (goniometer) od premca (0°) do krme za 180° po desni (+) in po levi (-) strani. Za določanje premčevega kota ne potrebujemo kompasa. Za določanje azimuta s pomočjo premčevega kota uporabimo lahko formulo ω = K + (± L)." },
  { cat: 5, q: "Koliko mora minimalno od obale pluti ladja ?", a: "Najmanj 300m od obale." },
  { cat: 3, q: "Katere osnovne podatke vsebuje vpisni list ?", a: "Vpisni list vsebuje naslednje podatke: \n1.stran vpisnega lista vsebuje:\nPodatke o organu, ki je vpisni list izdal, označbo čolna in ime čolna, če ga ima.\n2. stran:  List A,: PODATKI O ČOLNU IN MOTORJU \n3. stran : List A,: POSADKA IN NAMEN UPORABE ter OBMOČJE PLOVBE:\nOceansko območje,Odprto območje,Obalno območje (od 1 do 12 navtičnih milj od obale  oz. od temeljne črte,Območje zavetja,Obalno morje od 250 – 2000 m od obale za vodne skuterje.\n4.stran: List B: PODATKI O LASTNIKU. \n5.stran: List C: OBREMENITVE IN OPOMBE ter\n6. stran: DOVOLJENJE ZA PLOVBO" },
  { cat: 5, q: "Kdaj je potrebno opraviti osnovni pregled čolna ?", a: "Osnovni pregled se opravi pred vpisom čolna v vpisnik in tudi po vsaki njegovi obnovi ali rekonstrukciji.\nPri tem se opravijo tudi izmeritve čolna." },
  { cat: 3, q: "Kakšni so varnostni ukrepi v času polnjenja goriva v rezervar plovila?", a: "Ko se plovilo oskrbuje z gorivom, je potrebno paziti na:\n- kakšno gorivo bomo natočili v rezervoar,\n- da se ne uporablja odprtega ognja (ne kadimo), \n- da so odprtine, ki vodijo v bivalne prostore, zaprte (bencinski hlapi) \n- potrebno je dobro prezračevanje prostora, kjer sta motor in rezervoar goriva , \n- da je motor  ugasnjen,\n- da je pripravljen aparat za gašenje." },
  { cat: 6, q: "Kateri  zvočni signal  pomeni  »zavijam desno«?", a: "En kratki pisk." },
  { cat: 5, q: "Kateri čolni morajo izobesiti zastavo državne pripadnosti ?", a: "Državno zastavo morajo izobesiti čolni državnih organov, ostalim  čolnom pa (v domačih vodah) ni potrebno." },
  { cat: 4, q: "Kaj je devijacija ()?", a: "Devijacija je kot med magnetnim in kompasnim meridianom in je posledica ladijskega magnetizma. Podatek o devijaciji za določen  kurz se nahaja v tablici devijacije, ki je posebej izdelana za določeno plovilo." },
  { cat: 3, q: "Kaj storimo, če nam izvenkrmni motor ne vžge ?", a: "Če izvenkrmni motor ne vžge, pregledamo, če je dovolj goriva v rezervarju, če gorivo nemoteno prihaja do \nvplinjača, če je iskra na svečki in  če svečka ni zapackana." },
  { cat: 6, q: "Kateri zvočni signal  v ožinah ali kanalih pomeni, da  imamo  namen prehitevati drugo plovilo po desni?", a: "Dva dolga in en kratek pisk." },
  { cat: 3, q: "Katero plovilo se mora izogibati v primeru, če jadrnica prehiteva  motorni čoln in obstaja nevarnost trčenja?", a: "Izogiba se plovilo, ki prehiteva, torej jadrnica." },
  { cat: 3, q: "Kateri so osnovni nadomestni deli, ki jih je  priporočljivo imeti v plovilu ?", a: "Nadomestni deli, ki naj bi se nahajali na plovilu so vžigalne svečke, zatiči za propeler (krmni motor), jermen \n (stabilni motor), impeler od vodne črpalke, cevi za gorivo, filter goriva, objemke raznih dimenzij, žarnice \n (navig. luči,…), …" },
  { cat: 6, q: "Kateri zvočni signal v slabi vidljivosti  pomeni, da je ladja nesposobna za manevriranje, oz. da je ladja z omejeno sposobnostjo manevriranja,  omejena z ugrezom, ribiška ladja, da je jadrnica ali vlačilec ko vleče?", a: "Trije zvoki drug za drugim, od tega prvi dolg in dva kratka v intervalu ne več kot 2 minute." },
  { cat: 4, q: "Kašen pribor uporabljamo za delo na karti pri vodenju navigacije?", a: "Osnovni pribor za delo na karti vsebuje: dva navtična trikotnik, s katerima rišemo ali čitamo kurze in azimute; navtično šestilo, s katerim merimo in prenašamo oddaljenosti ter vrisujemo oziroma čitamo geografske koordinate; svinčnik in radirka." },
  { cat: 1, q: "Kaj je levante?", a: "Je prehoden, vlažen veter, ki nastane v zimskem času. Nastane v brezveterju in preide v burjo ali jugo. Ta veter je značilen za severni Jadran." },
  { cat: 6, q: "Kakšna je dolžnost plovila napram drugemu, ki se mora izogibati?", a: "Plovilo, ki ima prednost,  ne sme spreminjati svoje hitrosti in smeri plovbe." },
  { cat: 4, q: "Posebne oznake (IALA)", a: "Posebne oznake niso namenjene navigacijskemu označevanju, ampak z njimi označujemo posebna območja ali objekte, o katerih se lahko pomorščak informira iz pomorskih kart in drigih navigacijskih publikacij. Te oznake so npr. oznake oceanografskih postaj, oznake rekreativnih območij, oznake za kable in cevovode, oznake zavarovanih območij (npr. rezervat,..)" },
  { cat: 3, q: "Kaj je električna vžigalna svečka in čemu služi ?", a: "Vžigalna svečka je privita v glavo motorja in je zaključni del vžigalne naprave, ki sprejme visoko napetost el. toka in omogoči preskok iskre. Pri tem se vžge zmes benzina in zraka v izgorevalnem prostoru  \nmotorja." },
  { cat: 3, q: "Kakšne vrste hlajenja motorja se uporablja ?", a: "Za hlajenje motorjev na plovilih se uporablja zračno in vodno hlajenje motorja." },
  { cat: 5, q: "Kakšne morajo biti dimenzije označbe na gliserju ?", a: "Najmanjša dimenzija črk in številk mora biti : višina 20cm, širina 10 cm, širina linij 2cm,  medsebojna razdalja 2cm. Če so izmere večje mora biti ohranjeno predpisano razmerje." },
  { cat: 1, q: "Kaj je maestral?", a: "Maestral je prijeten, priobalni, termični veter, ki nastane zaradi tega, ker se kopno podnevi hitreje segreva kot morje. Pri nas piha iz smeri WNW, po večjem delu Jadrana iz smeri NW, na skrajno južnem Jadranu pa celo iz  smeri W. Pihati začne ob 10 uri, okrog 14 ure doseže največjo moč (okrog 4 BF) in preneha pihati pred sončnim zahodom." },
  { cat: 5, q: "Kako mora biti označeno mesto potapljanja (potapljač pod vodo)?", a: "Če je na boji ali na plovilu zastava A mednarodnega signalnega kodeksa ( prva vertikalna polovica zastave je  bele  barve in druga modra; zadnji del zastave ima obliko lastovičjega repa) pomeni, da je pod vodo potapljač in da moramo pluti počasi ter na primerni oddaljenosti. Športni potapljači označujejo mesto potapljanja z oranžno bojo,  premera vsaj 30 cm. Od oznake je potrebno  pluti na oddaljenosti  50 m in dlje. Boja ima lahko potapljaško zastavico rdeče barve z belima  diagonalama." },
  { cat: 3, q: "Katere so bistvene razlike med diesel in bencinskim (OTTO) motorjem ?", a: "Bistvena razlika je v  gorivu in v pripravi in vžigu goriva." },
  { cat: 3, q: "Koliko mora biti stara oseba in kakšen izpit mora imeti, če želi upravljati:  motorni čoln, gliser, čoln dolžine do 7 m  z motorjem do 7,35 kw in vodni skuter ?", a: "-\tmotorni čoln lahko upravlja oseba, ki je stara najmanj 16 let in ima opravljen izpit za voditelja čolna,\n-\tgliser lahko upravlja oseba, ki je stara najmanj 18 let in ima opravljen izpit za voditelja čolna,\n-\tčoln dolžine do 7 m z motorjem do 7,35 KW lahko upravlja oseba, ki je stara najmanj 16 let in ima opravljen preizkus znanja za upravljanje čolna\n-\tvodni skuter lahko upavlja oseba, ki je stara najmanj 16 let in ima opravljen preizkus znanja za upravljanje čolna." },
  { cat: 3, q: "Kaj je narobe, če nam diesel motor ugasne ?", a: "Če diesel motor sam od sebe ugasne je vzrok voda ali zrak v sistemu goriva (sistem je potrebno prezračiti) , \npomanjkanje goriva,..." },
  { cat: 3, q: "Katera dejanja so prepovedana v pristaniščih?", a: "-\tpremeščanje, menjanje ali odstranjevanje priveznih vrvi, sider in naveznih naprav drugega plovila, razen pri pristajanju ali zaradi preprečitve neposredne škode; \n-\toviranje dostopa do privezov; \n-\tprivezovanje plovil na naprave in predmete, ki niso namenjeni privezovanju; \n-\tsamovoljno premeščanje, menjavanje, odstranjevanje ali poškodovanje naprav in označb, namenjenih urejanju plovbe; \n-\tkurjenje odprtega ognja na obali ali na plovilu brez dovoljenja uprave; \n-\tčiščenje, barvanje ali strganje oplate plovila na način, ki lahko onesnaži morje; \n-\tprivezovanje čolnov na mestih, kjer to ni dovoljeno; \n-\timeti v pogonu ladijski vijak, razen za potrebe manevriranja; \n-\todmetavanje trdih in tekočih odpadkov in drugih predmetov v morje; \n-\tonesnaževanje zraka z izpuščanjem dima, saj in raznih plinov preko dovoljene stopnje;\n-\tizpuščati fekalne vode v morje; \n-\tuporaba priveznih mest v pristanišču za potopljene in nasedle čolne ali čolne, ki so poškodovani ali slabo vzdrževani." },
  { cat: 5, q: "Kaj so pomorski prekrški ?", a: "Pomorski prekrški so kršitve predpisov s področja pomorstva." },
  { cat: 2, q: "Od česa je odvisna stabilnost čolna ?", a: "Stabilnost čolna je odvisna od oblike trupa in od razporeditve tež v čolnu." },
  { cat: 5, q: "Kdaj prekrški prerastejo v kaznivo dejanje ?", a: "Kadar gre za hude kršitve, kjer nastane večja materialna škoda, težje telesne poškodbe ali smrtni primer in ko so ogrožena človeška življenja." },
  { cat: 1, q: "Naštej imena vetrov, ki pihajo na Jadranskem morju?", a: "- severnik (N) - tramontana\n     - sever-severovzhodnik (NNE) - burin \n     - severovzhodnik (NE) - burja\n     - vzhodnik (E) - levante\n     - jugovzhodnik (SE) - jugo, široko\n     - južnik (S) - oštro\n     - jugozahodnik (SW) - lebič, garbin\n     - zahodnik (W) - ponente\n     - severozahodnik (NW) - maestral" },
  { cat: 1, q: "Kako delimo oblake?", a: "Oblake delimo po višini, kjer se nahajajo, na visoke, srednje in nizke in po obliki na ciruse, kumuluse in stratuse, ter različne kombinacije le teh." },
  { cat: 3, q: "Koliko mora minimalno od obale pluti motorni čoln, ki ne glisira ?", a: "Najmanj 200 m od obale ." },
  { cat: 3, q: "Kako zaustavimo delovanje motorja ?", a: "Pri benzinskih motorjih je zaustavitev izvedena s prekinitvijo električnega vžiga, pri dieselski\nmotorjih pa s prekinitvijo dovoda goriva. To se izvede s pritiskom na gumb za zaustavitev, obratom\nkontaktnega ključa, premikom ročice za dovajanje goriva v skrajno zaprt položaj, itd." },
  { cat: 5, q: "Kaj se ugotavlja s pregledom čolna ?", a: "S pregledom se ugotavlja, ali je čoln po svoji konstrukciji, plovnih lastnostih in opreme sposoben za plovbo v določenih mejah plovbe." },
  { cat: 5, q: "Kdo izvaja nadzor nad varnostjo plovbe ?", a: "Nadzor nad varnostjo plovbe na morju izvaja Uprava Republike Slovenije za pomorstvo s pooblaščenimi uradnimi osebami - pristaniškimi nadzorniki iz Kapitanije in pomorskimi inšpektorji iz sektorja pomorske inšpekcije." },
  { cat: 6, q: "Kako se mora izogibati plovilo, ki se je dolžno izogibati?", a: "Plovilo, ki se je dolžno izogibati, ne sme sekati poti po premcu plovilu, ki ima prednost. Manever izogibanja mora biti pravočasen in odločen, da se popolnoma umakne s poti plovilu, ki ima prednost." },
  { cat: 3, q: "Kaj predstavlja bela luč ?", a: "Bela luč lahko pomeni:\n•\tplovilo, gledano v krmo \n•\tzasidrana ladja, krajša od 50 m.\n•\tplovilo krajše od 7 m in sicer: čoln na vesla, jadrnica, motorni čoln, ki ne razvija hitrosti nad 7 vozlov" },
  { cat: 3, q: "Na kaj moramo paziti pri pripravi izvenkrmnega motorja za zagon ?", a: "Pri motorju z vgrajenim rezervoarjem odpremo dovod goriva, pri motorjih z zunanjim rezervoarjem\npriklopimo cev za dovod goriva in s pomočjo ročne črpalke, ki je vgrajena na cevi, tlačimo gorivo,\ndokler ne občutimo upora. Omogočiti moramo vstop zraka v rezervoar (pri prenosnem rezervoarju odpremo \nventilček na čepu).\n- loputa za zrak (čok) mora biti zaprta,\n- ročica menjalnika naj bo v nevtralnem položaju, \n- pri ročnem zagonu preverimo, da je motor dobro pritrjen,\n- ko motor steče, odpremo čok, sicer se motor zaustavi zaradi prebogate zmesi benzina in zraka, \n- počakamo, da se segreje in med tem kontroliramo izpust hladilne vode." },
  { cat: 6, q: "Kateri zvočni signal v ožinah ali kanalih pomeni, da se ladja  približuje zavoju ?", a: "En dolg pisk, na katerega mora druga ladja odgovoriti enako z enim dolgim piskom." },
  { cat: 2, q: "Iz katerih materialov so  grajeni čolni?", a: "Za gradnjo čolna se uporabljajo različni materiali: les, kovina, plastika, guma, armirani beton, kombinirano (guma-plastika, guma-aluminij)." },
  { cat: 1, q: "Kaj storimo, ko opazimo prve znake približevanja nevihte?", a: "Čim prej poiščemo varno zavetje." },
  { cat: 5, q: "Katere vrste pregledov čolna poznamo ?", a: "Pregledi čolna so osnovni, redni in izredni." },
  { cat: 2, q: "Kateri so sestavni deli čolna?", a: "Sestavni deli čolna so gredelj, premčeva in krmna grodnica, rebra, oplata, zgornji del je paluba, če je nima (je odprtega tipa), je zgornji del zaključen z robnico." },
  { cat: 4, q: "Kakšne priročnike za plovbo poznate?", a: "Priročniki, ki jih uporabljamo za plovbo so: seznam svetilnikov, seznam radijskih svetilnikov, navtični letniki, razni vodniki za plovbo, tablice morskih men, katalog pomorskih kart, seznam kratic in znakov, oglasi za pomorščake, itd." },
  { cat: 5, q: "Kdaj mora izobesiti zastavo državne pripadnosti čoln, ki služi za osebne  namene ?", a: "Čoln za osebne namene mora pri plovbi v tujih notranjih morskih vodah izobesiti zastavo državne \npripadnosti in zastavo države  gostiteljice ( na krmi ima praviloma svojo zastavo, na jamboru ali na drugem višjem delu čolna pa zastavo gostiteljice)." },
  { cat: 4, q: "Kardinalne oznake (IALA)", a: "Kardinalne oznake kažejo, da je najgloblja voda v kvadrantu, ki  je poimenovan z oznako.\nVrhnje znamenje v obliki dvojnega stožca je podnevi najpomembnejša karakteristika vsake kardinalne oznake. Oznaka je običajno boja s stebrom ali drogom, rumeno črne barve (kombinacija pasov barve je različna za vsak kvadrant), dvojni stožci se nahajajo na vrhu in so postavljeni glede na kvadrant različno (npr. za N kvadrant oba z vrhovoma navzgor, za S kvadrant oba z vrhovoma navzdol, za E kvadrant z osnovnima ploskvama drug proti drugemu, za W pa z vrhovoma drug proti drugemu). Kardinalne oznake imajo tudi poseben sistem belih utripajočih luči ( N kvadrant neprekinjeni zelo kratki ali kratki bliski, E trije zelo kratki ali kratki bliski, katerim sledi premor, S kvadrant šest zelo kratkih ali kratkih, sledi dolgi blisk in nato premor, W kvadrant devet zelo kratkih ali kratkih bliskov, katerim sledi premor)." },
  { cat: 2, q: "Kako se obnaša čoln pri plovbi  z vetrom v krmo ?", a: "Pri plovbi čolna z vetrom v krmo se čoln  ziblje, slabše drži smer in lahko povzroča tresljaje zaradi izhajanja propelerja  iz vode." },
  { cat: 3, q: "Na kaj moramo biti pozorni pri delovanju motorja med plovbo ?", a: "Med plovbo poslušamo delovanje motorja in opazujemo instrumente za nadzor delovanja motorja.\nPosebno moramo biti pozorni na alarme in opozorilne lučke, ker le ti se pojavijo, ko je z delovanjem\nmotorja nekaj narobe." },
  { cat: 5, q: "Kateri organ  v R Sloveniji vodi vpisnik morskih čolnov ?", a: "Vpisnik morskih čolnov vodi Uprava RS za pomorstvo Koper in njeni izpostavi v Izoli in Piranu." },
  { cat: 6, q: "Kateri zvočni signal v slabi vidljivosti pomeni, da je ladja na mehanični pogon v plovbi?", a: "En dolg zvok v intervalih ne več kot 2 minute." },
  { cat: 2, q: "Kako delimo čolne?", a: "Čolne delimo po obliki, vrsti pogona,  namenu in materialu iz katerega so grajeni" },
  { cat: 5, q: "Kaj obsegajo notranje morske vode ?", a: "Notranje morske vode obsegajo morje med temeljno črto teritorialnega morja in obalo (morje med črto, ki povezuje skrajne zunanje točke zunanjih otokov in kopno, zalivi, pristanišča)." },
  { cat: 4, q: "3.\tKaj pomeni, če se pri križanju kurzev dveh plovil premčev kot ali azimut spreminja?", a: "Če se premčev kot ali azimut spreminja tako, da se povečuje, bo opazovano  plovilo plulo mimo  za krmo našega plovila. Če se premčev kot ali azimut zmanjšuje, bo opazovano plovilo plulo mimo  pred premcem našega plovila." },
  { cat: 6, q: "Kaj  razumemo za plovbo pod težjimi pogoji?", a: "Plovba pod težjimi pogoji je plovba mimo raznih ovir, v megliv  dežju, v močnem vetru, v kanalih in ožinah, pod mostovi, itd." },
  { cat: 3, q: "Kako delimo motorje z notranjim izgorevanjem ?", a: "- Glede na gorivo in način vžiga na benzinske (OTTO)  in dieselske motorje.\n- Po načinu delovanja ločimo na štiritaktne in dvotaktne.\n- Po načinu hlajenja na tekočinsko hlajenje in zračno hlajenje." },
  { cat: 3, q: "Kdaj ugasnemo motor  pri pristajanju čolna?", a: "Pri pristajanju čolna ugasnemo motor šele, ko je čoln dokončno privezan ob obalo." },
  { cat: 3, q: "Kaj je narobe, če motor teče neenakomerno in izpušča takte ?", a: "Če motor teče neenakomerno in izpušča takte pomeni, da ena od svečk ne dela ali so poškodovani kabli  (prebijajo)." },
  { cat: 2, q: "Kaj je ugrez ?", a: "Ugrez je navpična razdalja med najnižjo točko čolna in vodno črto." },
  { cat: 3, q: "Zakaj je pomembno , kakšno svečko bomo privili glede na  dolžino navoja ?", a: "Če privijemo svečko z dolgim navojem tam, kjer je predvidena svečka s kratkim navojem, lahko \npride do poškodbe bata motorja." },
  { cat: 2, q: "Kaj je četverovez ?", a: "Četverovez je način priveza plovila s štirimi vrvmi in sicer tako, da sta dve vrvi privezani na obalo in dve na      morsko stran, bodisi na sidri na boji ali na droga (marine). Proti obali je lahko obrnjen premec ali pa krma. V praksi je najpogostejši  način privezovanja tako, da sta dve vrvi narazen privezani na obalo, ena (ali več) na bojo." },
  { cat: 3, q: "Kaj se zgodi, če je toplotna vrednost svečke previsoka ?", a: "Svečka ne doseže svoje delovne temperature in se zapacka." },
  { cat: 2, q: "Kako se meri širina čolna ?", a: "Širina čolna se meri na glavnem rebru med zunanjima robovoma oplate." },
  { cat: 1, q: "Kako se obnaša čoln  pri plovbi proti vetru ?", a: "Pri plovbi v veter, torej tudi v valove, se hitrost čolna zmanjša, propeler ne deluje enakomerno zaradi vzdolžnega \nguganja, pojavljajo se vibracije in konstrukcija čolna trpi. Priporočljivo je pluti s premcem odmaknjenim \npribližno 25 stopinj od smeri vetra in valov." },
  { cat: 6, q: "Katera je predpisana oprema in območje plovbe za čoln do 5 m dolžine ?", a: "Za čoln dolžine do 5 m je predpisan minimum opreme:\n-\tsidro ali drugo sredstvo za sidranje z najmanj 20 metrov dolgo vrvjo ali verigo za sidranje in tri vrvi za\n-\tprivez skupne dolžine najmanj 30 metrov ustrezne jakosti\n-\tdve vesli s tremi palci ali rogovilami oziroma drugo pomožno pogonsko napravo\n-\tvedro s korcem\n-\tluči in dnevne oznake po predpisih o izogibanju trčenju na morju\n-\tkonveksno ogledalo (le gliser, ki se uporablja za smučanje na vodi)\nObmočje plovbe je obalno območje do 4Nm od obale." },
  { cat: 6, q: "Kakšna sredstva uporabljamo za reševanje oseb iz vode?", a: "Za reševanje oseb iz vode uporabljamo: obroč za reševanje (opremljen je lahko s 25 m dolgo vrvjo, s posebno svetilko ali z dimnim signalom oranžne barve), rešilni pas, rešilni jopič, rešilni splav različnih dimenzij, napihljive blazine, vrvi, itd." },
  { cat: 4, q: "Sistem pomorskih oznak IALA", a: "Ta sistem vsebuje pravila, ki se uporabljajo za fiksne in plavajoče oznake (med te ne spadajo svetilniki, sektorske luči in oznake pokrite smeri, ladje in velike navigacijske boje).\nSistem pomorskih oznak predvideva pet vrst oznak in sicer laterarne oznake (označujejo levo in desno stran plovne poti), kardinalne oznake (označujejo območja plovnih voda), oznake osamljene nevarnosti, oznake varnih voda, posebne oznake (te niso postavljene kot navigacijske oznake, ampak služijo za označevanje kakega posebnega območja  ali objekta, npr. pri nas rumene boje pri Belih skalah, ki označujejo zaščiteno območje)." },
  { cat: 3, q: "Kako lahko preventivno ukrepamo, da preprečimo požar na plovilu ?", a: "Da ne pride do požara, lahko preventivno poskrbimo z naslednjimi ukrepi:\n- paziti moramo, da je dno čolna ni mastno,\n-da ne pretakamo goriva na samem čolnu, posebno  med vožnjo,\n- da se izogibamo  zalogam goriva na čolnu v netestiranih posodah, \n- da kontroliramo in po potrebi nadomestimo poškodovane električne kable in cevi goriva,\n- po možnosti vgradimo  v strojnico detektorje, ki nas opozarjajo na dim - ogenj, \n- če je le možno, vgradimo avtomatsko gašenje strojnice,\n- če čoln zapustimo za dalj časa, izklopimo glavno električno stikalo oz. odklopimo kleme akumulatorja." },
  { cat: 6, q: "Kakšen mora biti manever izogibanja?", a: "Manever izogibanja mora biti pravočasen in odločen. Vsaka sprememba smeri in hitrosti mora biti dovolj velika in razločna, da je za drugo plovilo nedvoumna." },
  { cat: 2, q: "Kako mora biti razporejen tovor na čolnu ?", a: "Tovor na čolnu mora biti enakomerno razporejen po plovilu in pritrjen." },
  { cat: 3, q: "Katera je predpisana oprema in območje plovbe za čoln nad 5m in čoln s kabino do 7m dolžine?", a: "Za čoln dolžine nad 5 m in čoln do 7 m s kabino je predpisan minimum opreme:\nsidro z najmanj 30 metrov dolgo vrvjo ali verigo za sidranje in tri vrvi za privez skupne dolžine najmanj 40 metrov ustrezne jakosti\n-\tpomožno pogonsko napravo (motor ali jadra) ali VHF GMDSS postajo ali tri rdeče rakete s padalom\n-\tvedro s korcem ali ročno črpalko\n-\tluči in dnevne oznake po predpisih o izogibanju trčenju na morju\n-\tkonveksno ogledalo (le gliser, ki se uporablja za smučanje na vodi)\n-\ttri rdeče bakle\n-\tkompas\nMed plovbo mora imeti rešilne jopiče v tolikšnem številu, kolikor oseb se nahaja na čolnu.\nObmočje plovbe je obalno območje do 4Nm proti odprtemu morju, merjeno od osnovne črte teritorialnega morja." },
  { cat: 3, q: "Kaj so lahko vzroki požara na čolnu?", a: "Vzroki požara na čolnu so lahko:  uporaba odprtega ognja, kratek stik na električni instalaciji, nepravilno ravnanje s pogonskim gorivom, trčenje čolna, nepravilno prezračevanje strojnice (predvsem pri oskrbi z gorivom), elekt. naprav, ki niso  zavarovane proti iskrenju, itd." },
  { cat: 3, q: "Kako izplujemo iz priveznega mesta ?", a: "Izplovitev iz priveza izvršimo tako, da najprej prižgemo motor in nato odvežemo vrvi. Po potrebi se s pomočjo čolnarskega kavlja  odrinemo od obale, od sosednja čolna, preverimo, da ob čolnu ni ovir za varno izplovitev (npr. izpuščene vrvi  boje, vrvi sosednjega čolna, ipd.), pazimo, da pri izplovitvi ne poškodujemo sosednjega čolna (odrsamo oplato, zvijemo ograjo, ipd.) in ko smo dovolj oddaljeni od obale, vključimo pogon čolna (prestavimo  ročico  menjalnika iz položaja prostega teka)." },
  { cat: 4, q: "Laterarne oznake (IALA)", a: "Laterarne oznake se uporabljajo za označevanje leve in desne strani plovne poti ali plovnega kanala. V coni A (Evropa, Afrika, Avstralija in Azija, razen Japonske, Filipinov in Koreje) se leva stran ponoči in podnevi označuje z rdečo barvo, desna pa z zeleno. V coni B  (severna in južna Amerika, Japonska, Koreja, Filipini) je leva zelena, desna rdeča." },
  { cat: 1, q: "Kaj so poletne vročinske nevihte?", a: "Poletne nevihte so lokalne in bolj pogoste v severnem Jadranu. Največkrat pridejo iznenada iz severnega dela   Italije, iz smeri NW do SW potujejo s hitrostjo 15-20 vozlov. Ponavadi se pojavijo pri vedrem, tihem in   soparnem vremenu in so lokalnega značaja. Ko opazimo prve znake približevanja nevihte, je nevihta že zelo  blizu. Najprej opazimo temen kopast oblak ponavadi nekje na zahodu, ta hitro preide v vertikalno izražen  kumulonimbus, ki se nahaja v centru nevihte. Zračni pritisk pada, horizont v zahodni smeri se pomrači, pojavi se grmenje in bliskanje, deževni naliv in sunkoviti, močni udarci vetra. Take nevihte so kratkotrajne in ko  minejo, se spet povrne lepo vreme z brezveterjem." },
  { cat: 4, q: "Pomorske oznake IALA v slovenskem morju", a: "V našem morju imamo kardinalno oznako na svetilniku Debeli rtič (W kvadrant, stožca z vrhovoma drug proti drugemu, svetilnik je rumene barve  s širokim črnim pasom v sredini).\nVsi vhodi v pristanišča, kanal bazena III koprskega pristanišča, imajo laterarne oznake (leva je označena z rdečo, desna z zeleno), oznaka varnih vodah – boja na sredini koprskega zaliva (vertikalni beli in rdeči pasovi), posebne oznake – označena zavarovana območja z rumenimi bojami (naravni spomeniki ) Debeli rtič, Bele skale, rt Madona. \n\nPri obalni plovbi vzdolž zahodne obale Istre bomo opazili (glej karto Grado-Rovinj  100-15) večje število oznak osamljene nevarnosti in kardinalnih oznak." },
  { cat: 3, q: "Katere čolne ni potrebno vpisati v vpisnik čolnov ?", a: "V vpisnik čolnov ni potrebno vpisati čolna, krajšega od 3 metrov, razen če ima motorni pogon z močjo več kot 3,7 kW." },
  { cat: 4, q: "Katere objekte izbiramo pri določanju položaja čolna s pomočjo azimutov?", a: "Pri določanju položaja čolna z azimuti izbiramo merkantne objekte kot so rti, zvoniki, cerkve, gradovi, stolpi, tovarniški dimniki, izrazit vrh hriba ipd. Azimute lahko nato vrišemo v pomorsko karto ( ωp ) le, če je opazovan objekt vrisan na karti ( npr. tovarniški dimnik, cerkev ipd.)." },
  { cat: 3, q: "Katere so dobre in slabe lastnosti vgrajenih motorjev  ?", a: "Dobre lastnosti: so stabilni, imajo miren tek, daljšo življenjsko dobo, dopuščajo večje moči.\nSlabe lastnosti: rabijo prostor v čolnu, vzdrževanje je težje zaradi majhnega prostora, zahtevajo trdnejšo konstrukcijo čolna in slabši izkoristek vijaka zaradi nagnjene osi (nagnjenost osi se precej\nizboljša z \"V\" vgradnjo motorja)." },
  { cat: 5, q: "Kaj storimo s stvarmi, ki jih najdemo v  obalnem morju ?", a: "Najdeno stvar na morju je treba prijaviti policijski postaji." },
  { cat: 5, q: "Kako delimo  morje?", a: "Morje delimo na notranje morske vode in teritorialno morje." },
  { cat: 3, q: "Kakšno gorivo uporabljajo diesel motorji?", a: "Diesel motorji uporabljajo za gorivo plinsko olje (nafta)." },
  { cat: 3, q: "Kakšno gorivo uporabljajo dvotaktni bencinski motorji?", a: "Dvotaktni bencinski motorji uporabljajo za gorivo mešanico olja in bencina v razmerju, ki ga predpiše proizvajalec motorja." },
  { cat: 5, q: "Kje poteka temeljna črta teritorialnega morja ?", a: "Temeljna črta je črta srednjega nivoja nizkih nižjih vod ali ravna črta, ki zapira vhod v zaliv. \nPri določanju temeljne črte teritorialnega morja se kot del obale štejejo tudi najbolj izpostavljene stalne pristaniške zgradbe, ki so sestavni del pristaniškega sistema. V tujini spaja tudi zunanje rte zalivov in skrajne zunanje točke najbolj oddaljenih otokov in zapira vhode v ustja rek." },
  { cat: 1, q: "Na kaj moramo biti pozorni pri vremenski napovedi ?", a: "Predvsem moramo biti pozorni na opozorila, ki napovedujejo nevihte in poslabšanje vremena." },
  { cat: 4, q: "2.\tKdaj obstaja nevarnost trčenja dveh plovil pri križanju kurzev?", a: "Nevarnost trčenja pri križanju kurzev obstaja takrat, ko se premčev kot ali azimut, ki ga merimo v časovnih presledkih na drugo plovilo, bistveno ne spreminja." },
  { cat: 1, q: "Kje dobimo vremensko napoved?", a: "Dokler smo še na kopnem vremensko napoved dobimo iz različnih medijev in na oglasnih deskah pristaniških  kapitanij ali v marinah. Med plovbo pa lahko poslušamo radijska poročila, ki so namenjena pomorščakom na frekvencah, ki jih imamo na razpolago." },
  { cat: 3, q: "Kako delimo električne vžigalne svečke ?", a: "Delimo jih  po toplotni vrednosti in po obliki (dolgi in kratki navoj)." },
  { cat: 5, q: "Kaj obsega nadzor nad varnostjo plovbe glede čolnov?", a: "Nadzor obsega  nad : \n-\tusposobljenostjo za upravljanje s čolni,\n-\tdovoljenega števila oseb na čolnu,\n-\tprevozom oseb in blaga s čolni,\n-\tizvajanjem plovbnega režima čolnov,\n-\tsposobnostjo čolnov za plovbo,\n-\tpredpisano opremo čolnov." },
  { cat: 2, q: "Kaj je čoln ?", a: "Čoln je plovilo, ki meri v dolžino manj kot 24 m." },
  { cat: 5, q: "Kaj obsega carinsko območje ?", a: "Carinsko območje obsega celotno teritorialno morje in notranje morske vode ter pas 5 km v notranjost od obale." },
  { cat: 3, q: "Kako deluje  podmazovanje pri sodobnejših dvotaktnih motorjih ?", a: "Da bi se dodalo v motor pri različnih režimih delovanja ravno pravšnja količina olja za podmazovanje,\nse proizvajajo motorji, ki imajo olje v odvojenem rezervarju in ga posebna naprava sproti glede na\nobrate in obremenitev motorja primeša v benzin, ki vstopa v motor." },
  { cat: 6, q: "Kateri zvočni signal v ožinah ali kanalih pomeni, da imamo  namen prehitevati drugo plovilo po levi?", a: "Dva dolga in dva kratka piska." },
  { cat: 4, q: "Oznaka varnih voda (IALA)", a: "Oznaka varnih voda kaže, da so vode okoli oznake plovne in brez nevarnosti za navigacijo. Oblika oznake je sferična boja, pobarvana z rdečimi in belimi navpičnimi progami, ali pa enako pobarvan steber ali drog.Oznaka z lučjo je bele barve, ritem pa je lahko izofazen, prekinjajoč, dolg blisk  vsakih 10 sekund ali Morse črka A ( . -)." },
  { cat: 5, q: "Koliko smejo plavati kopalci od obale ?", a: "Na naravni plaži največ do 150 m od obale." },
  { cat: 6, q: "Kateri zvočni signal v slabi vidljivosti pomeni, da je  ladja na mehanični pogon na plovni poti in se ne premika?", a: "Dva dolga zvoka v presledku 2 sekund in intervalu ne več kot 2 minute." },
  { cat: 5, q: "Koliko je široko teritorialno morje ?", a: "Teritorialno morje je pas, širok 12 Nm, merjeno navzven od osnovne ali temeljne črte teritorialnega morja." },
  { cat: 1, q: "Kaj je burja?", a: "Burja je suh, mrzel in sunkovit veter. Predvsem je to severovzhodnik, čeprav lahko piha vse od severa do vzhoda. Burja nastane, ko se razvijeta dve področji zračnega pritiska nad srednjo Evropo in Jadranom ali Sredozemljem. Pogosto se pojavi tudi lokalna burja, ki nastane zaradi ohlajevanja zraka nad kraškimi dolinami, ki se potem vali čez obronke hribov ali čez sedla. Taka burja zapiha iznenada, je kratkotrajna, pogosto pa tudi zelo močna. Burja piha čez vse leto, vendar je predvsem zimski veter. Lahko traja nekaj ur (poleti), nekaj dni, pa vse do teden ali dva (pozimi). Včasih doseže orkansko moč, tako močna burja ponavadi traja do dva dni. Burja piha od primorskih hribov navzdol proti morju in ustvari ostre valove, ki se lomijo in penijo. Anticiklonalna burja je, ko prevladuje visok zračni pritisk, vreme je lepo in vedro. Ciklonalno ali mračno burjo ustvarijo cikloni, ki se približujejo vzhodni Jadranski obali, spremlja jo oblačno in deževno vreme." },
  { cat: 1, q: "Kaj je pomembno pri sidranju ?", a: "Pri sidranju  izberemo točko sidranja upoštevajoč globino morja, vrsto dna, zavarovanost pred vremenskimi vplivi (veter, valovi, tokovi). Uporabiti moramo primerno sidro in sidrno vrv ter spustiti dovolj sidrne vrvi dolžine vsaj 3x globine morja, da se lahko sidro dobro zarije v dno (pesek, mulj,..)." },
  { cat: 3, q: "Kako delimo motorje glede na vgradnjo v čoln ?", a: "Delimo jih na vgrajene, krmne in \"Z\" pogon." },
  { cat: 3, q: "Kako deluje podmazovnje pri štiritaktnih motorjih ?", a: "Pri štiritaktnih motorjih podmazovanje deluje tako, da oljna črpalka črpa olje iz oljnega korita (karterja) \nin ga tlači po mazalnih kanalih do mazalnih mest, od koder se olje  steka v oljno korito. To je tlačno mazanje." },
  { cat: 5, q: "Kje mora biti na čolnu označba in ime ter kakšne barve?", a: "-\tOznačba čolna mora biti na obeh straneh premca čolna, ime pa sme biti samo na krmi ali na obeh bokih krme. \n-\tOznačba čolna mora biti v barvi, ki se vidno loči od barve čolna." },
  { cat: 5, q: "Kje se moramo pri prehodu državne meje s čolnom prijaviti in kakšne listine je potrebno predložiti organom  na mejnem  prehodu?", a: "Če nameravamo vpluti v notranje morske vode druge države, moramo vpluti  v najbližje pristanišče, kjer je mednarodni mejni prehod .Pri prijavi predložimo vse potrebne listine, ki jih ta država zahteva.\nObičajno so te listine potni listi, vpisni list plovila, zavarovalna polica, potrdilo o usposobljenosti za upravljanje čolna, če je čoln opremljen s pomorsko radio postajo, pa potrdilo o usposobljenosti za delo s \npostajo." },
  { cat: 6, q: "15.\tKateri zvočni signal pomeni  »zavijam levo«?", a: "Dva kratka piska." },
  { cat: 1, q: "Kako se obnaša čoln pri plovbi z vetrom v pol krme ?", a: "Čoln sili s premcem proti veteru in teži k temu, da bi se postavil bočno v veter in valove. Pri takšni  plovbi čoln slabo drži smer, posvetiti je treba več pozornosti krmarjenju." },
  { cat: 3, q: "Kaj storimo, če nam izvenkrmni motor pade v morje ?", a: "Če nam izvenkrmni motor pade v morje, dvignemo motor iz morja in ga  čimprej operemo s sladko vodo.   \nElektrično napeljavo posušimo in poškropimo z WD 40 in motor čimprej damo v pogon.\nIzvenkrmne motorje, ki jih pogosto odstranjujemo s čolna (hranimo doma), je priporočljivo dodatno zavarovati \nin sicer tako, da motor dodatno zavarujemo s krajšo vrvico (motor privežemo na čoln)." },
  { cat: 4, q: "Kako določimo položaj z dvema azimutoma?", a: "V čim krajšem časovnem razmaku izmerimo dva azimuta na dva objekta, kompasna azimuta spremenimo v prava azimuta (upoštevamo skupni popravek),in šele nato ju narišemo na karto, presečišče obeh azimutov predstavlja položaj čolna v času snemanja azimutov. Idealen kot med azimutoma je 90°; paziti moramo, da kot med azimutoma ni oster ali top, ker bi v tem primeru verjetno prišlo do večje napake v položaju." },
  { cat: 5, q: "Kakšen je režim plovbe v teritorialnih vodah ?", a: "Plovilo, ki pluje skozi teritorialno morje (tranzitira) tuje države se ni dolžno javljati oblastem. Temu pravimo neškodljiv prehod teritorjalnega morja. V primeru  vplutja v notranje morske vode pa se mora prijaviti  v najbližjem pristanišču, kjer je mednarodni mejni prehod." },
  { cat: 2, q: "Kako ravnamo pri vdoru vode ?", a: "Pri vdoru vode ugotovimo vzrok vdora vode, kje in na kakšen način vdira voda. Takoj pričnemo z zaustavitvijo \nvdora vode (odvisno od  načina vdora vode uporabimo razne pripomočke kot. npr. ponjavo, čepe, hitrovezni \ncement, ipd.) in z izčrpavanjem vode s pomočjo črpalk in/ali s pomočjo različnih posod. Osebe (tovor) lahko premikamo po čolnu tako, da z nagibom čolna (odvisno na katerem mestu vdira voda, npr. v višini vodne črte) in     \nzmanjšamo oz. zaustavimo vdor vode v čoln. Če ugotovimo, da kljub vsem naporom nismo uspeli zaustaviti \nprodiranje vode v čoln, ga usmerimo proti obali in skušamo nasesti na plitvini. Odvisno od okoliščin, pri vdoru vode najprej poskrbimo,  da si osebe nadenejo rešilne jopiče." },
  { cat: 2, q: "Kako moramo pluti mimo zasidranih čolnov ob naravni plaži?", a: "V primeru, da vidimo zasidrane čolne ob naravni plaži, bomo pluli po zunanji strani zasidranih čolnov in nikakor med njimi oz. med njimi in obalo, ker lahko predvidevamo, da so med čolni in obalo plavalci. Če se čolni nahajajo bliže obali pa moramo vsekakor pluti vsaj 200 m , če glisiramo vsaj 250 in dlje od obale." },
  { cat: 4, q: "Kaj je magnetni kompas?", a: "Magnetni kompas je naprava, s pomočjo katere določimo magnetni meridian." },
  { cat: 1, q: "Kaj je tramontana?", a: "Tramontana je veter, ki piha iz severa (N), je veter prehodnega značaja. Je kratkotrajen in piha v vseh letnih obdobjih, je  lahko močan  in nevaren veter. Običajno preide v burjo." },
  { cat: 2, q: "Katere oblike čolnov poznamo?", a: "Poznamo: spodrivni-deplasmanski (pasara, guc), pol spodrivni (pilotina), drsni  čolni (gliser).\nLočimo tudi: enotrupne, dvotrupne (katamarane), tritrupne (trimarane)." },
  { cat: 3, q: "Katera je predpisana oprema in območje plovbe za čoln s kabino nad 7 m dolžine?", a: "-\tsidro primerne teže z najmanj 40 metrov dolgo vrvjo ali verigo za sidranje ter tri vrvi za privez skupne dolžine najmanj 45 metrov ustrezne jakosti\n-\tpomožno pogonsko napravo (motor ali jadra) ali VHF GMDSS postajo ali tri rdeče rakete s padalom\n-\tvedro s korcem ali ročno črpalko\n-\tnajmanj en prenosni gasilni aparat na prah\n-\tluči in dnevne oznake po predpisih o izogibanju trčenju na morju\n-\ttri rdeče bakle\n-\tkomplet prve pomoči\n-\tbaterijsko svetilko\n-\tkomplet orodja za vzdrževanje mehanskih naprav\n-\tkompas\n-\tpriročnike za plovbo\n-\tpomorske karte področja, kjer pluje, s priborom\nMed plovbo mora imeti rešilne jopiče v tolikšnem številu, kolikor oseb se nahaja na čolnu.\nTak čoln lahko pluje v celotnem obalnem morju, se pravi od 12 Nm od osnovne črte teritorialnega morja." },
  { cat: 5, q: "Koliko mora minimalno od obale pluti čoln, ki glisira ?", a: "Najmanj 250 m od obale." },
  { cat: 1, q: "Kaj je burin?", a: "Je priobalni nočni veter, ki nastane, ker se kopno po zahodu sonca hitreje ohlaja kot morje. Piha od sončnega zahoda do sončnega vzhoda iz smeri NNE do ENE." },
  { cat: 2, q: "Kakšne vrste vrvi poznamo ?", a: "Po materialu izdelave poznamo  kovinske, vrvi iz naravnih vlaken in vrvi iz umetnih vlaken." },
  { cat: 3, q: "Kaj obsega vzdrževanje čolna ?", a: "Vzdrževanje se razlikuje glede na vrsto materiala iz katerega je čoln grajen. Predvsem je potrebno čoln po uporabi očistiti in oprati, vsaj enkrat letno  barvati (dno čolna z antivegetativno barvo, po potrebi tudi ostale dele), zamenjati cink protektorje in opraviti servis pogonskega motorja." },
  { cat: 4, q: "Kakšno karto uporabljamo pri navigaciji?", a: "Pri navigaciji uporabljamo karto, ki je izdelana po metodi imenovani Merkatorjeva projekcija. \nNa takšni karti koti in smeri ustrezajo kotom in smerem v naravi. Kurzna linija je ravna črta in seka meridiane pod istim kotom. Na desni in levi strani je merilo, na katerem določimo geografsko širino in merimo oddaljenost (1' = 1 Nm). Zgoraj in spodaj se nahaja merilo, na katerem določamo geografsko dolžino." },
  { cat: 2, q: "Zakaj uporabljamo vrvi ?", a: "Vrvi uporabljamo za privez plovila, za dvigovanje - spuščanje tovora, za opravila v ladjedelništvu, v  ribištvu, pomorskih športih, jadranju,itd." },
  { cat: 3, q: "4.\tKatero od plovil na motorni pogon se je dolžno izogibati v primeru križanja kurzev ?", a: "Izogiba se tisto motorno plovilo, ki vidi drugo plovilo preko svojega desnega boka, razen, če gre za plovilo, ki je nesposobno za manevriranje, ki  ima omejeno sposobnost za manevriranje, če je jadrnica oz. če je zaposleno z ribolovom." },
  { cat: 4, q: "Kaj je skupni popravek (ps)?", a: "Skupni popravek je vsota devijacije in varijacije in ga  uporabimo pri pretvarjanju kurzov in azimutov iz pravih v kompasne in obratno.  \nps = (± var) + (± " },
  { cat: 1, q: "Kaj predstavlja kumulonimbus?", a: "To je ogromen nevihtni oblak vertikalnega razvoja, ki ima na vrhu kapo v obliki nakovala. Takšen oblak spremljajo močne padavine vseh oblik, bliskanje in grmenje ter močan nevihtni veter." },
  { cat: 3, q: "Kako deluje podmazovnje  pri dvotaktnem bencinskem (OTTO) motorju ?", a: "Pri dvotaktnem motorju se motor podmazuje z oljem v mešanici. Mešanico pripravimo tako, da olje primešamo   \nbenzinu v določenem razmerju,    ki ga predpiše proizvajalec.  Mešanica služi kot pogonsko gorivo in \npodmazuje notranje dele motorja." },
  { cat: 6, q: "Kako ravnamo, če nam oseba med plovbo pade v vodo ?", a: "V takem primeru čoln takoj obrnemo  v stran padca osebe v vodo (s tem oddaljimo krmo čolna od osebe v vodi ) in zmanjšamo hitrost.Takoj odvržemo obroč ali drugo sredstvo in ga istočasno bodrimo z besedami. S čolnom se  približamo in postavimo tako, da ostane oseba v privetrju (to velja za manjše in lahke čolne, ) in ga nato dvignemo v  čoln ter če je potrebno mu nudimo prvo pomoč." },
  { cat: 6, q: "Kateri zvočni signal v slabi vidljivosti pomeni, da je pilotski čoln med pilotažo?", a: "Štirje kratki piski." },
  { cat: 6, q: "Katera protipožarna sredstva poznamo ?", a: "Protipožarna sredstva so: vodna črpalka,  ročni gasilni aparati (CO2, prah, pena), pesek, razna prekrivala (ponjave), itd." },
  { cat: 4, q: "Kako delimo pomorske karte?", a: "Pomorske karte delimo na: informativne, navigacijske in pomožne." },
  { cat: 2, q: "Kakšna sredstva lahko uporabimo za zaustavitev vdora vode v čoln ?", a: "Za zaustavitev vdora vode lahko uporabimo ponjavo, razne čepe, odeje, blazine, deske, vzglavnike, hitrovezni cement, objemke, ipd." },
  { cat: 5, q: "Ali ima reševalec pri reševanju stvari pravico do nagrade ?", a: "Za  reševanje plovila ali stvari s plovila  reševalcu pripada nagrada." },
  { cat: 6, q: "Kaj pomeni zvočni signal iz petih kratkih piskov?", a: "Zvočni signal iz petih kratkih piskov je signal za vzbujanje pozornosti druge ladje. Lahko se ga uporabi tudi v obliki svetlobnega signala." },
  { cat: 4, q: "Zakaj je potrebno pretvarjati azimute in kurze?", a: "Če na pomorsko karto vrišemo kurzno linijo (kurz pravi) in bi pluli v tem kurzu s pomočjo magnetnega kompasa, moramo vedeti, kolikšen je kurz kompasni. Kurz kompasni dobimo, če od kurza pravega odštejemo skupni popravek, zato uporabimo formulo:  Kk = Kp - (± ps)\nPri določanju položaja čolna z azimuti s pomočjo magnetnega kompasa  izmerimo na opazovani objekt (npr. svetilnik, rt,..)  azimut kompasni. Preden azimut vrišemo na karto, ga moramo spremeniti v azimut pravi po formuli : ωp = ωk + (± ps)." },
  { cat: 3, q: "Kateri so osnovni instrumenti za nadzorovanje delovanja motorja ?", a: "instrument za prikazovanje temperature hladilne tekočine (termometer)\ninstrument za prikazovanje pritiska olja (manometer)\ninstrument za prikazovanje stanja akumulatorja (voltmeter)\ninstrument za prikazovanje polnjenja akumulatorja (ampermeter)\nmerilec obratov motorja\nRazen navedenih instrumentov je na armaturni plošči vgrajen tudi merilec goriva, ki sicer ne spada med inštrumente za nadzor delovanja motorja, je pa zelo pomemben, ker nam kaže količino goriva v rezervarju." },
  { cat: 6, q: "Kje  in v kolikšnem času moramo prijaviti pomorsko nezgodo čolna ?", a: "Pomorsko nezgodo čolna je potrebno prijaviti takoj ( iz objektivnih razlogo, npr, da ste poškodovani in v bollnici pa najkasneje v 3 dneh) Upravi RS za pomorstvo (URSP) oz. njenih dveh izpostavah (Izola, Piran), odvisno v katerem vpisniku je vpisan čoln. v kolikor je prišlo do trčenja plovil je potrebno počakati pooblaščeno uradno osebo URSP, da si ogleda kraj in ugotovi dejansko stanje, sicer je predvidena visoka sankcija." },
  { cat: 3, q: "Katere listine se morajo nahajati  med plovbo na  čolnu, ki je krajši od 3 m in z motornim pogonom do 3,7 kw - čoln, ki ni vpisan v vpisnik čolnov ( neregistriran čoln )?", a: "Upravljalec čolna  mora imeti  potrdilo o opravljenem preizkusu znanja, priporoča pa se, da ima pri sebi dokazilo o lastništvu (neregistriranega) čolna in motorja (npr. račun čolna in motorja).." },
  { cat: 6, q: "Kateri  zvočni signal v slabi vidljivosti dajejo plovila krajša od 12m?", a: "Učinkovit zvočni signal v intervalih ne daljših od 2 minuti." },
  { cat: 6, q: "Kaj moramo vedeti, če izbruhne požar ?", a: "Če izbruhne požar, je potrebno čim prej:\n- zapreti dovod goriva,\n- prekiniti izvor električnega toka,\n- zapreti dovod zraka,\n- gasiti požar s primernimi sredstvi (tekočih goriv ne smemo gasiti z vodo, ker plavajo na površini vode, s tem bi \npožar samo širili)." },
  { cat: 4, q: "Kako lahko v nočni plovbi ugotovimo, kateri svetilnik opazujemo?", a: "Približen položaj čolna nam je znan. Na karti pogledamo karakteristike svetilnikov na tem območju in  primerjamo karakteristiko opazovanega svetilnika s karakteristiko, ki je napisana na pomorski karti. Karakteristike  svetilnikov se medsebojno razlikujejo, da ne bi prišlo do zamenjave. Karakteristiko določenega svetilnika lahko dobimo tudi v spisku svetilnikov." },
  { cat: 4, q: "Kaj je kurz (K)?", a: "Kurz je kot med vzdolžnico ladje v smeri plovbe in meridianom. Kurz se šteje od severnega dela meridiana v smeri urnega kazalca  od 0° do 360°. Ločimo kurz pravi (Kp), kurz magnetni (Km) in kurz kompasni (Kk). Črta, ki jo vrišemo na pomorsko karto, po kateri naj bi plula ladja, je kurzna linija." },
  { cat: 2, q: "Zakaj je potrebno čoln vzdrževati ?", a: "Čoln je potrebno vzdrževati, ker je nenehno izpostavljen različnim zunanjim negativnim vplivom, ki na njem in opremi povzročajo obrabo in poškodbe. Sem štejemo tudi obrastlost podvodnega dna, ki vpliva na hitrost in  porabo goriva." },
  { cat: 3, q: "Katere so dobre in slabe lastnosti krmnih motorjev ?", a: "Dobre lastnosti : lahko dostopni za popravila , lahko jih snamemo zaradi transportiranja ali shranjevanja,\npovečane manevrske sposobnosti, lahko priplujemo na nizko vodo, ker lahko dvignemo propeler (nogo) \niz vode, itd.\nSlabe lastnosti :  izpostavljen je zunanjim vplivom, čoln ima  zatego, kar vpliva na stabilnost čolna." },
  { cat: 3, q: "Kako deluje  štiritaktni diesel motor, naštej takte ?", a: "PRVI TAKT - je sesalni, bat s pomikom navzdol sesa sveži zrak v valj.\nDRUGI TAKT - je kompresijski, bat se pomika navzgor in zrak komprimira ( stiska).\nTRETJI TAKT - je ekspanzija ( delo ), nastane po samovžigu goriva, ki je bilo vbrizgano\npod visokim tlakom v izgorevalni prostor nad valjem motorja, pri tem potisne bat navzdol in \nopravi delo. \nČETRTI TAKT - je izpušni, bat iztisne ostanke izgorelih plinov v izpušni sistem." },
  { cat: 5, q: "Kje poteka državna meja ?", a: "Državna meja poteka po zunanjem robu teritorialnega morja." },
  { cat: 6, q: "Kateri zvočni signal v ožinah ali kanalih pomeni, da se  strinjamo  z  namero drugega plovila za prehitevanje?", a: "En dolg, en kratek en dolg in en kratek pisk." },
  { cat: 4, q: "Kakšne naloge rešujemo na navigacijski karti?", a: "Na navigacijskih kartah  rišemo in čitamo geografske koordinate (položaje), merimo kurze in azimute, rišemo kurze in azimute in merimo razdalje." },
  { cat: 4, q: "Kaj so geografske koordinate?", a: "Geografske koordinate so geografska širina in geografska dolžina.\nGeografska širina (φ; Lat.) se meri od ekvatorja (0°) proti severu (+) in proti jugu (-) do tečajev za 90°.\nGeografska dolžina (  ; Lon.) se meri od začetnega meridiana (0°, Greenwich) proti vzhodu (+) in proti zahodu (-) za 180°.\nZ geografskimi koordinatami je  določena katerakoli točka na zemeljski obli (v našem primeru položaj čolna)." },
  { cat: 2, q: "Kako se obnaša čoln pri plovbi z bočnim vetrom ?", a: "Takšna plovba je neprimerna in nevarna, čoln se močno ziblje. Valovi ga lahko naplavijo ali prevrnejo." },
  { cat: 3, q: "Kakšno gorivo uporabljajo štiritaktni bencinski motorji ?", a: "Štiritaktni bencinski motorji uporabljajo za gorivo bencin." },
  { cat: 6, q: "Kaj so lahko vzroki za vdor vode v čoln ?", a: "Vzroki so lahko poškodbe pri trčenju, nasedanju, pri udarcu ob obalo, pri lomu plovila zaradi slabega morja in nepravilne plovbe v valove, popustitev tesnjenja cevi pri vsisu morske vode, ipd." },
  { cat: 3, q: "Kateri motorji uporabljajo električno vžigalno svečko ?", a: "Imajo jo vsi bencinski ( OTTO) motorji." },
  { cat: 3, q: "Kako deluje štiritaktni bencinski (OTTO) motor, naštej takte ?", a: "PRVI TAKT - je sesalni, v valj s pomikom bata navzdol, sesamo zmes benzina in zraka.\nDRUGI TAKT - je kompresijski, bat zmes benzina in zraka komprimira ( stiska ).\nTRETJI TAKT - je ekspanzija ali delovni takt, ko s pomočjo iskre na svečki vžgemo \nkomprimirano zmes, ki potisne bat navzdol in opravi delo.\nČETRTI TAKT- je izpušni , bat iztisne ostanke izgorelih plinov v izpušni sistem." },
  { cat: 4, q: "Kako plujemo v megli?", a: "V megli naj ne bi pluli, če pa že moramo, to storimo tako, da zmanjšamo hitrost in povečamo previdnost. Poostrimo opazovanje in poslušanje in uporabljamo signale, ki so predpisani za plovbo v megli. Paziti moramo na položaj čolna, da ne bi prišlo do nasedanja ali trčenja v obalo ali kak drugi objekt." },
  { cat: 3, q: "Katere luči označujejo plovila na mehanski pogon in v katerih kotih so vidne?", a: "Ladjo oz. čoln  na mehanski pogon, ko pluje, mora imeti:\n•\tbelo jamborna luč, ki sveti v loku 225° po premcu (112,5˚ levo in 112,5˚ desno)\n•\tbočni luči, ki svetita v loku 112,5˚ in sicer od vzdolžnice plovila po premcu levo rdeča luč in desno zelena luč\n•\t belo krmno luč, ki sveti v kotu 135˚ (67,5˚ po krmi levo in desno)\n•\tče je ladja daljša od 50 m, mora imeti dodatno belo jamborno luč na krmnem jamborju, ki sveti 225˚ po premcu in je postavljena višje od  prednje jamborne luči\n•\tče je motorni čoln krajši od 7 m sme imeti samo belo krožno luč, če je mogoče tudi bočne luči." },
  { cat: 5, q: "Kakšen je režim plovbe v tuje notranje morske vode ?", a: "Pri vplutju v tuje notranje morske vode je potrebno  prijaviti prihod čolna v prvem pristanišču, odprtem za mednarodni pomorski promet (kapitanija, policija, carina) in šele nato lahko nadaljujemo s plovbo proti željenem kraju." },
  { cat: 3, q: "Katere listine je potrebno priložiti k vlogi za vpis morskega čolna ?", a: "1. Zahtevi za prvi vpis čolna je treba priložiti: \n-\tlistino, ki dokazuje lastništvo čolna in motorja (račun, izjava o samogradnji čolna z računi o nabavljenem materialu, celotna veriga listin kot na primer prodajna, darilna ali druga pogodba, sklep sodišča o dedovanju in podobno), \n-\tcarinsko deklaracijo, \n-\tpotrdilo o izbrisu, če je bil čoln vpisan v drugem vpisniku (v primeru, da je čoln vpisan v vpisniku na območju Republike Slovenije, pridobi to potrdilo organ sam), \n-\tdokazilo o izbrisu motorja, če je bil vpisan na drugem čolnu, \n-\tspričevalo o gradnji čolna in spričevalo o motorju ali deklaracijo o skladnosti in potrdilo proizvajalca v skladu s pravilnikom o rekreacijskih plovilih, \n-\tlistine po predpisih o davku na dodano vrednost, če je tako predpisano, \n-\tdokazilo o obveznem zavarovanju proti odgovornosti za škodo povzročeno tretjim osebam\n2. Zahtevi za spremembo vpisa je treba priložiti dokaz o dejstvu, ki narekuje vpis te spremembe." },
  { cat: 4, q: "Kaj so znaki in kratice na pomorskih kartah?", a: "Zaradi pravilnega tolmačenja znakov in kratic, ki se nahajajo na pomorskih kartah, izdajajo ustanove, ki se ukvarjajo z izdelavo kart posebno brošuro, katera vsebuje vse znake in kratice, vključno z opisom njihovega pomena. Uporabnik karte naj bi se seznanil vsaj s tistimi znaki in kraticami, ki se najpogosteje uporabljajo." },
  { cat: 1, q: "Kaj je stabilnost čolna ?", a: "Stabilnost je lastnost čolna, da se upira nagibanju pod vplivom delovanja zunanjih sil (veter, valovi) in da se po prenehanju njihovega delovanja vrne v prvotni ravnotežen položaj." },
  { cat: 2, q: "Kaj pomeni, da sidro \"orje\" in kaj storiti v tem primeru ?", a: "Pomeni, da sidro ni prijelo za dno, potrebno je ponoviti sidranje, spustiti več vrvi, uporabiti primerno sidro. \nV primeru, ko vsi poskusi niso bili uspešni, se je treba sidranju odpovedati." },
  { cat: 4, q: "Uporaba radarja pri obalni navigaciji", a: "Radar uporabljamo za določanje položaja in merjenje oddaljenosti v priobalni plovbi. V pogojih, ko je zmanjšana vidljivost (megla, dež, noč,..) je radar nepogrešljivo pomožno sredstvo, ki omogoča nadaljevanje plovbe, vendar z veliko mero previdnosti." },
  { cat: 4, q: "Čitanje pomorske karte.", a: "Kandidatu se pokažejo določeni znaki in kratice na karti (npr. znak za čeri, izobato, vrsta morskega dna, ipd) katerih pomen mora obrazložiti. Znaki in kratice so prikazani v publikaciji »Kartografski ključ znakov in krajšav«." },
  { cat: 2, q: "Kako ravnamo pri nasedanju čolna ?", a: "- Preverimo, ali je prišlo do poškodbe trupa in vdora vode, kakšno je dno in na katerem delu je čoln nasedel.\n-Če ni prišlo do vdora vode, ugotovimo možnost, da se čoln odstrani z nasedlega mesta z uporabo lastnega pogona, z natezanjem sidra,  z vleko (pogonom)  drugega  čolna,čakamo na visoko vodo, premeščamo tovor,...\n- Kadar voda vdre v čoln, jo poskušamo ustaviti ali omejiti ter izčrpati iz plovila. Nato nasedlo plovilo začnemo reševati. \n-Plovilo s poškodovanim podvodnim ali nadvodnim delom oplate vlečemo tako, da je nepoškodovan \n del v  smeri plovbe.\n-Jadrnico (z globokim gredljem) nagnemo (na vrv, ki gre iz glave jamborja, pritrdimo tovor, osebe, ali je celo vleče   drugo plovilo tako, da se jadrnica nagne) in zaplujemo proti večjim globinam." },
  { cat: 1, q: "Kako ravnamo, če se med plovbo pojavi požar na čolnu ?", a: "Zmanjšamo hitrost in obrnemo čoln tako, da je požar v zaveterju. \nTakoj uporabimo vsa razpoložljiva sredstva za gašenje. Če požar ne uspemo pogasiti se lahko odločimo za nasedanje  ali potapljanje čolna na majhni globini." },
  { cat: 4, q: "Odčitajte koordinate danega položaja na  karti ?", a: "Na pomorski karti je že vrisan položaj čolna (krogec s piko v sredini), kandidat mora odčitati geografsko širino in geografsko širino danega položaja čolna." },
  { cat: 2, q: "Na kakšni dovoljeni minimalni razdalji sme čoln pluti od zunanjega roba označenega kopališča?", a: "S plovilom se smemo približati (pluti) do 50 m od označenega kopališča (boj). V primeru, da sega  zunanji označeni rob kopališča pod 150 m od obale, mora čoln pluti na taki razdalji od obale kopališča, ki ne sme biti krajša od 200 m od obale, če glisira 250 m in če je ladja 300 m." },
  { cat: 3, q: "Kaj je narobe, če motor ne drži minimalnih obratov?", a: "Če motor ne drži minimalnih obratov, pomeni, da je slabo nastavljen minimum, da je šoba v vplinjaču zamašena ali da je nepravilna toplotna vrednost svečke." },
  { cat: 3, q: "Kaj je narobe, če vgrajenega motorja ni mogoče zagnati?", a: "Če vgrajenega motorja ni mogoče zagnati, je največkrat razlog, da je akumulator prazen, da ne deluje zaganjalnik ali da je okvara na električni napeljavi." },
  { cat: 3, q: "Kolikokrat se obrne ročična gred, ko motor opravi delovni takt ?", a: "Enkrat pri dvotaktnih motorjih in dakrat pri štiritaktnih motorjih." },
  { cat: 2, q: "Kaj so lahko vzroki nasedanja čolna ?", a: "Vzroki so lahko: nasedanje zaradi nepravilne plovbe, okvare naprav, višja sila, malomarnost posadke, itd" },
  { cat: 1, q: "Kako določimo smer vetra?", a: "Smer vetra določimo po smeri, iz katere veter piha." },
  { cat: 1, q: "Kako določimo moč vetra in stanje morja brez uporabe instrumentov?", a: "Moč vetra in stanje morja brez uporabe instrumentov določimo s pomočjo  Beaufortove (Bofor) lestvice (0-12 Bf) za veter in Douglasove lestvice za stanje morja (0-9, višna, oblika, lomljenje, penjenje, kotalenje, itd), ki nam pomaga določiti moč vetra). Stopnje moči vetra in morja so dololčene na podlagi opisa stanja morja npr. morje gladko kot olje: stanje morja je 0, veter 0, itn." },
  { cat: 3, q: "Zakaj je potrebno podmazovnje v motorju ?", a: "Podmazovanje motorja je potrebno zaradi zmanjševanja trenja, obrabe drsnih površin in zaradi \nodvajanja toplote." },
  { cat: 3, q: "Kakšne sisteme  vodno hlajenih motorjev  poznamo ?", a: "Odprt sistem, kjer voda  iz morja s pomočjo črpalke  po opravljeni cirkulaciji v motorju nazaj odteče v morje.\nZaprt sistem, kjer vedno ista hladilna tekočina cirkulira s pomočjo črpalke v motorju, ki jo hladi v \nhladilniku voda iz morja." },
  { cat: 2, q: "Kako poteka manever sidranja ?", a: "Manever sidranja se izvede tako, da se s počasno vožnjo najprej približamo točki sidranja. Neposredno pred prihodom na  točko sidranja zapeljemo počasi nazaj (umirimo čoln) in odvržemo sidro. Izpustimo dovolj sidrne vrvi, da sidro »dobro drži«." },
  { cat: 1, q: "Katero je območje plovbe  in katere so omejitve glede plovbe vodnega skuterja?", a: "Z vodnim skuterjem  moramo  pluti minimalno 250m od obale in maksimalno do 2000m od obale. Plovba je dovoljena od sončnega vzhoda do sončnega zahoda ob normalnih vremenskih razmerah." },
  { cat: 3, q: "Kakšne so posledice neprimernega podmazovanja ?", a: "Zaradi neprimernega podmazovanja  pride do predčasne izrabe motorja, v ekstremnem primeru tudi \ndo blokade motorja (zaribavanje)." },
  { cat: 6, q: "Kakšna sredstva uporabljamo za gašenje tekočega goriva ?", a: "Za gašenje tekočega goriva uporabljamo gasilne aparate (prah in CO2), pesek, odeje in različna prekrivala ,..." },
  { cat: 3, q: "Katera naprava lahko nadomesti vplinjač ?", a: "Naprava za vbrizg goriva." },
  { cat: 3, q: "Na kakšne načine se podmazujejo motorji pri delovanju?", a: "Motorji se podmazujejo z oplakovanjem, z mešanico pri dvotaktnih motorjih in  s tlačnim podmazovanjem." },
  { cat: 1, q: "Kaj je ponente?", a: "Piha iz zahodne (W) smeri in je nevihtni veter." },
  { cat: 5, q: "Ali ima voditelj čolna za reševanje ljudi pravico do nagrade in ali je dolžan  reševati ljudi na morju ?", a: "Voditelj čolna mora reševati ljudi v stiski na morju razen, če bi z reševanjem ogrožal sebe ali svoje plovilo. Za reševanje ljudi ne  pripada nagrada." },
  { cat: 4, q: "Kaj je azimut (ω)?", a: "Azimut je kot med linijo opazovalca na opazovani objekt in  meridianom . Azimut se meri od meridiana v smeri urnega kazalca  do linije opazovalca na objekt  in sicer od 0° do 360°. Razlikujemo azimut pravi (ωp), azimut magnetni (ωm) in azimut kompasni (ωk). Za določanje azimuta potrebujemo kompas z merilno napravo." },
  { cat: 4, q: "Naštejte nekaj načinov določanja položaja čolna na morju?", a: "Položaj s kompasom (mora imeti merilno napravo) lahko določimo z  azimutom in pokrito smerjo,  z dvema azimutoma na isti objekt v časovnem razmaku, z dvema azimutoma na dva objekta, z dvema razdaljama (radar), z uporabo GPS-a, itd." },
  { cat: 6, q: "Kaj pomeni kratek in kaj dolg pisk?", a: "Kratek pisk pomeni zvok, ki traja 1 sekundo, dolg pa zvok, ki traja 4-5- sekund." },
  { cat: 2, q: "Katere vrste vrvi se najbolj uporabljajo in zakaj ?", a: "Najbolj se uporabljajo vrvi iz umetnih vlaken, ker so bolj elastične, odporne proti vlagi in glede na isto debelino so bolj čvrste od  vrvi iz naravnih vlaken." },
  { cat: 4, q: "Kaj je varijacija?", a: "Varijacija je posledica zemeljskega magnetizma, zato se magnetni poli in meridiani ne pokrivajo s pravimi. Varijacija je kot med pravim in magnetnim meridianom in je lahko + E ali - W. Za različne točke na zemeljski obli je varijacija različna in tudi s časom se spreminja. Podatek o varijaciji za določeno leto in  letne spremembe dobimo na pomorskih kartah v roži vetrov. Še bolj natančno vrednost varijacije dobimo iz baze podatkov, ki jih vsebujejo navigacijski računalniški programi (npr. GPS)." },
  { cat: 5, q: "Kdaj je potrebno opraviti redni pregled čolna ?", a: "Redni pregled čolna  se opravlje glede na njegovo namembnost  v naslednjih časovnih obdobjih :\n-\tza javni prevoz oseb ali smučanje na vodi  vsako leto ,\n-\tza druge gospodarske namene in javne namene (kapitanija, policija itn.) vsaki dve leti ,\n-\tza osebne namene vsakih pet let ." },
  { cat: 3, q: "Kako  vzdržujemo  akumulator ?", a: "Pri akumulatorju je potrebno občasno preveriti količino elektrolita (z destilirano vodo razredčena žveplena    \nkislina) v celicah in po potrebi dolijemo le destilirano vodo, čistimo kontakte in pazimo, da akumulatorja ne   \nizpraznimo preveč z uporabo potrošnikov, ko motor (polnjenje) ne deluje." },
  { cat: 2, q: "Katere dolžine čolna poznamo ?", a: "Poznamo dolžino čez vse in dolžino na konstrukcijski vodni črti." },
  { cat: 1, q: "Kako vplivata morski tok in veter na plovbo?", a: "Morski tok in veter vplivata na plovbo tako, da  zmanjšujeta  ali povečujeta hitrost čolna ali  ga zanašata, odvisno od smeri toka in vetra napram plovbi čolna.\nPri plovbi iz položaja P1 v položaj P2  bi iz pomorske karte odčitali določen kurz.(Kp). Če bi pluli v navedenem kurzu pod vplivom morskega toka in vetra, bi prišlo do zanosa čolna in zaradi tega nebi prispeli v P2, ampak bi pluli mimo. \nZato bi morali, da prispemo v položaj P2, upoštevati zanos  in za to vrednost kurz tudi popraviti." },
  { cat: 1, q: "Kaj je hitrost vetra?", a: "Hitrost vetra je pot, ki jo opravi zračna masa v določeni časovni enoti. Izrazimo jo lahko v m/s, km/h ali v vozlih (Nm/h)." },
  { cat: 4, q: "Oznake osamljene nevarnosti (IALA)", a: "Oznaka osamljene nevarnosti označuje nevarnost za navigacijo majhne površine, ki je obkrožena s plovnimi vodami. Vrhnje znamenje je v obliki  dveh črnih krogel, označuje jo tudi bela luč po 2 bliska v skupini. Ponavadi sta krogli na stebru ali drogu, barva je črna z enim ali več širokimi rdečimi vodoravnimi pasovi." },
  { cat: 6, q: "Katere luči in znamenja so predpisane v pravilih o izogibanju trčenj na morju?", a: "Luči, ki se nanašajo na pravila o izogibanju trčenj na morju so jamborna luč, bočni luči, krmna luč, krožna luč, luč za vleko in bliskajoča luč. Barve luči so bela, rdeča, zelena in rumena Znamenja  so v obliki krogle, stožca in  cilindra. Znamenja se uporabljajo tudi v kombinaciji npr. dve krogli, krogla-dvojni stožec-krogla, stožca spojena z vrhovoma, stožca, spojena z osnovnima ploskvama itd. Znamenja se uporabljajo podnevi, luči pa od sončnega zahoda do vzhoda, pri zmanjšani vidljivosti in v drugih primerih, kadar je to potrebno. Znamenja so črne barve." },
  { cat: 3, q: "Katere so dobre lastnosti \"Z\" pogona ?", a: "Kombinacija vgrajenega in izven krmnega motorja ima združene vse dobre lastnosti enega in drugega \npogona. Motor je vgrajen v zadnji del čolna, vijak pa je skupaj s peto gibljiv kot pri krmnem motorju. Zato ima  \ntak čoln zelo dobre manevrske sposobnosti." },
  { cat: 6, q: "Kaj je dolžna storiti oseba, ki upravlja čoln oz. lastnik v primeru izrednega dogodka (trčenje, potopitev, požar ipd.)?", a: "V primeru izrednega dogodka je dolžan upravljalec čolna  oz. lastnik o tem takoj obvestiti Upravo RS za pomorstvo oz. njeno izpostavo, kjer je čoln vpisan, v opravičenih primerih (če je npr. v bolnici) pa najkasneje v treh dneh." },
  { cat: 3, q: "Kateri element v motorju skrbi, da bo temperatura hladilne tekočine konstantna ?", a: "Za konstantno temperaturo hladilne tekočine v motorju med obratovanjem skrbi  termostat." },
  { cat: 6, q: "Katere luči svetijo v krogu 360˚?", a: "V krogu 360˚ svetijo luči, ki označujejo:\n•\tzasidrane ladje \n•\t jadrnice nad 20 m  \n•\tribiške ladje \n•\tladje nesposobne za manevriranje \n•\tladje z omejeno sposobnostjo manevriranja\n•\tčolni dolžine do 7 m, razen tistih, ki  razvijajo hitrost nad 7 vozlov" },
  { cat: 1, q: "Kako nastane veter?", a: "Veter nastane, ko se začnejo zračne mase premikati iz področja visokega zračnega pritiska proti področju nizkega zračnega pritiska." },
  { cat: 2, q: "Kako se meri višina čolna ?", a: "Višina čolna se meri od spodnjega roba gredlja do zgornjega roba palube ali robnice." },
  { cat: 4, q: "Kaj je navigacija?", a: "Navigacija je znanost in veščina vodenja plovila po varni poti." },
  { cat: 2, q: "Kdaj čoln glisira?", a: "Čoln glisira, ko drsi po vodni površini." },
  { cat: 1, q: "Kaj je jugo?", a: "Je topel in vlažen veter, piha iz smeri ESE do SSE. Največkrat je to ciklonalni veter, ki nastane, ko se nahaja področje visokega zračnega pritiska nad vzhodnim Sredozemljem in nizkega nad Evropo. Piha vzdolž Jadranske obale in povzroča razburkano morje, spremljajo ga oblačno vreme in dolgotrajno deževje. Jugo je močan veter in razvije velike valove, vendar ga smatramo za manj nevarnega kot burjo, ker se počasi razvija. Valovi so bolj pravilne oblike in so pri isti višini daljši, kot valovi, ki jih povzroči burja." },
  { cat: 1, q: "S čim opišemo vreme?", a: "Vreme opišemo z vremenskimi pojavi, oblaki, vetrom, temperaturo, vlago, zračnim pritiskom." },
  { cat: 4, q: "Kako izmerimo globino morja?", a: "Najbolj enostaven način izmeritve globine je s pomočjo vrvi in nanjo privezane uteži. Danes se vse bolj pogosto uporablja ultrazvočni globinomer (echosounder). Podatek o globini potrebujemo zaradi varne plovbe, varnega priveza, sidranja, lahko pa nam pomaga tudi pri oceni položaja plovila." },
  { cat: 3, q: "Kaj je vplinjač ?", a: "Vplinjač je naprava, ki poskrbi, da motor vsesa pravilno zmes zraka in benzina." },
  { cat: 1, q: "Kaj je morski horizont in kako ga delimo?", a: "Morski horizont ali obzorje je krožnica, ki omejuje vidik opazovalca na morju in je tista črta, ki loči morje od neba. Horizont delimo na 360° ali na kardinalne (N, S, E, W) in interkardinalne smeri (NE, SE, SW, NW). Če želimo še bolj natančno določiti smer, npr iz katere smeri piha  veter, uporabimo še vmesne smeri (NNE, ENE,ESE, SSE, SSW, WSW, WNW, NNW) ali pa uporabimo podelitev horizonta na stopinje." },
  { cat: 2, q: "Naštej nekaj vrst sider ?", a: "Admiralitetno sidro, Danforth sidro, sidro goba,  sidro maček, patentno (dežnik) sidro, plužno sidro, Hallovo sidro,.." },
  { cat: 2, q: "Naštej strani  čolna, preko katerih vidimo neki drugi objekt (čoln, nevaren plavajoči predmet, ipd)!", a: "Po premcu, levo po premcu, bočno levo, levo po krmi, po krmi, desno po krmi, bočno desno, desno po premcu." },
  { cat: 3, q: "Kako deluje dvotaktni bencinski (OTTO) motor, naštej takte ?", a: "PRVI TAKT- DELOVNA FAZA - iskra svečke vžge mešanico v izgorevalnem prostoru  in \npotisne bat  navzdol. Obenem pa pod seboj stiska svežo mešanico (goriva, zraka in olja ) v ohišje \ngredi. Proti koncu tega giba odpre rob bata izpušni kanal in izpušni plini izhajajo v izpušno cev.\nKmalu za izpušnim kanalom odpre bat tudi sesalni kanal, skozi katerega vdre sveža mešanica iz \nohišja gredi v valj in pomaga iztisniti zaostale izgorele pline iz valja.\n\nDRUGI TAKT - KOMPRESIJA - bat med gibanjem navzgor zapre pretočni kanal, nato izpušni\nter stiska mešanico do zgornje mrtve točke. S tem je zaključen delovni ciklus in se prične naslednji." },
  { cat: 1, q: "Kaj je lebič (garbin)?", a: "Je nevihtni jugozahodni (SW) veter z velikimi valovi in spremljajo ga močne padavine. Na Jadranski obali ogroža tista pristanišča, ki niso zaščitena pred SW. Poleti nastopi kot veter lokalne toplotne nevihte. V drugih letnih časih ima lebič izrazite ciklonalne (frontalne) karakteristike. Pihati začne, ko se pojavi južno ali jugo-zahodno od Jadrana anticiklon, obenem se s severa približuje močan ciklon. Takrat na Jadranu začne pihati južni ali jugozahodni veter. Zaradi gibanja ciklona vzdolž Jadrana, veter čez nekaj časa naglo obrne na SW in doseže nevihtno moč, to je lebič. Največjo moč vetra spremlja najnižji zračni pritisk. Takoj po prehodu ciklona se  začne moč vetra zmanjševati." },
  { cat: 6, q: "Katero opremo mora imeti upravljalec vodnega skuterja?", a: "Upravljalec vodnega skuterja  mora imeti na sebi rešilni jopič." },
  { cat: 1, q: "Kaj je oštro?", a: "Je prehoden in kratkotrajen veter, piha iz južne (S) smeri." },
  { cat: 2, q: "Kako pristajamo bočno ob obalo?", a: "Pri pristajanju z bokom čolna ob obalo zmanjšamo hitrost, preverimo smer in moč vetra ter vodni tok, postavimo bokobrane, pripravimo privezne vrvi in čolnarski kavelj. Pod kotom 30 do 45 stopinj usmerimo čoln proti obali. Ko se dovolj približamo obali, uporabimo čolnarski kavelj za odrivanje ali vleko, pred tem postavimo v nevtralni položaj ročico menjalnika (po potrebi zavozimo nazaj). Nato privežemo premec in nato krmo čolna ob obalo (zavozimo nazaj, list krmila obrnemo proti obali)." },
  { cat: 2, q: "Zakaj je potrebno, da najprej privežemo premec čolna?", a: "V primeru bočnega pristajanja ob obalo je potrebno najprej privezati premec, ker krmo lahko približamo k obali s pomočjo pogona (zavozimo s primerno močjo nazaj, list krmila obrnemo proti obali)." },
  { cat: 2, q: "Kako izbiramo primerno sidro in sidrno vrv?", a: "Teža sidra naj bo 1-1,5 kg po dolžinskem metru plovila na vodni liniji. Sidrna vrv mora biti dovolj čvrsta in naj meri vsaj 3 x globine, kjer nameravamo sidriti. Glede na vrsto dna izberemo pravilno obliko sidra. Da sidro dobro drži, je priporočljivo, da je na sidro pritrjena veriga v dolžini cca 2 m, na katero je privezana na drugem koncu sidrna vrv." },
  { cat: 3, q: "Kaj je narobe, če nam motor pokašljuje preden ugasne?", a: "Če motor pokašljuje preden ugasne, je vzrok v dotoku goriva (malo goriva, umazan filter, zamašen ali prekinjen dotok goriva, ...)." },
  { cat: 3, q: "Katero je osnovno orodje, ki ga je priporočljivo imeti v plovilu?", a: "Osnovno orodje za odpravo manjših okvar predvsem na motorju je manjše kladivo, več vrst izvijačev, različne klešče, ključ za svečke, univerzalni ključ, ključi (natikalni, vilice, zvezda velikosti 10,11,12,13,17), dleta." },
  { cat: 4, q: "Katere merske enote se uporabljajo pri navigaciji?", a: "Enota za merjenje razdalje je navtična milja in znaša 1852 m. Na karti predstavlja eno minuto (1̀). Manjša enota je kabel in znaša 185,2 m. Enota za merjenje hitrosti je vozel in predstavlja 1 Nm/h." },
  { cat: 4, q: "Kako delimo navigacijske karte?", a: "Navigacijske karte delimo na: generalne karte, ki pokrivajo velika področja (celi svet, oceani, morja, veliki zalivi); kurzne karte, ki pokrivajo dele posameznih morij in se uporabljajo za risanje kurzov in navigacijo; obalne karte se uporabljajo za plovbo ob obali; plane, ki predstavljajo manjše površine kot npr. sidrišča, pristanišča, plovne kanale, itd." },
  { cat: 4, q: "Kaj so informativne karte?", a: "Informativne karte vsebujejo različne podatke, ki jih lahko uporabimo pri navigaciji. To so npr. meteorološki in hidrološki podatki, podatki o morskih tokovih in podobno." },
  { cat: 4, q: "GPS pokaže položaj čolna φ=XX XX.x N in λ=XXX XX.x E, vriši ta položaj na karto?", a: "Na podlagi danih koordinat (φ in λ) na pomorski karti mora kandidat narisati položaj čolna." },
  { cat: 5, q: "Katera so območja plovbe čolnov?", a: "Območja plovbe čolnov so:\n- A - oceansko območje\n- B - odprto območje\n- C - obalno območje\n- D - območje zavetja" },
  { cat: 5, q: "Kdaj sme čoln izpluti?", a: "Čoln sme izpluti:\n- če je glede na konstrukcijske, plovne lastnosti in opremo ugotovljena njegova sposobnost za plovbo,\n- če je zanj izdano dovoljenje za plovbo,\n- če ga upravlja usposobljena oseba." },
  { cat: 5, q: "Kakšne so kazni za lažje prekrške?", a: "Za prekrške posameznika so predvidene denarne kazni na kraju samem in sicer do 850 EUR." },
  { cat: 5, q: "Katere listine mora pri sebi imeti upravljalec čolna med plovbo?", a: "Med plovbo mora upravljalec čolna imeti pri sebi veljaven vpisni list, potrdilo o sklenjenem zavarovanju proti odgovornosti za škodo povzročeno tretjim osebam in potrdilo za upravljanje s čolnom." },
  { cat: 6, q: "Katere so dolžnosti voditelja čolna pri upravljanju s čolnom?", a: "Voditelj čolna mora, da bi lahko ocenil situacijo in nevarnost trčenja, ustrezno opazovati vizualno in s poslušanjem." },
  { cat: 2, q: "Ali je pri vdoru vode bolje luknjo zapirati od zunaj ali od znotraj in zakaj?", a: "Če je izvedljivo, je bolje luknjo zapirati z zunanje strani, ker pritisk vode ponjavo, čep ali drug tesnilni material pritiska ob trup čolna. Če luknjo zapiramo z notranje strani, voda material potiska stran od odprtine, zato ga moramo dodatno podpreti ali zagozditi." },
  { cat: 6, q: "Kako prepoznamo najpogostejše nočne luči plovil?", a: "Najpogostejše nočne luči prepoznamo po barvi, položaju in kotu vidnosti. Motorno plovilo v plovbi ima belo jamborno luč, rdečo levo bočno luč, zeleno desno bočno luč in belo krmno luč. Jadrnica v plovbi ima rdečo in zeleno bočno luč ter belo krmno luč. Zasidran čoln oziroma ladja ima belo krožno luč. Plovilo nesposobno za manevriranje ima dve rdeči krožni luči ena nad drugo. Plovilo z omejeno sposobnostjo manevriranja ima rdečo, belo in rdečo krožno luč navpično." },
  { cat: 6, q: "Kako prepoznamo najpogostejša dnevna znamenja plovil?", a: "Dnevna znamenja so črne oblike, ki se uporabljajo podnevi. Zasidrano plovilo kaže eno črno kroglo. Plovilo nesposobno za manevriranje kaže dve črni krogli navpično. Plovilo z omejeno sposobnostjo manevriranja kaže kroglo, dvojni stožec oziroma romb in kroglo. Plovilo omejeno z ugrezom kaže črn valj. Jadrnica, ki pluje tudi z motorjem, kaže črn stožec z vrhom navzdol. Ribiško plovilo kaže dva stožca z vrhovoma skupaj." },
  { cat: 6, q: "Kako se izogibata dve motorni plovili pri čelnem srečanju?", a: "Pri čelnem srečanju dveh motornih plovil, kadar obstaja nevarnost trčenja, morata obe plovili spremeniti smer v desno, tako da se srečata z levima bokoma. Manever mora biti pravočasen in dovolj očiten." },
  { cat: 6, q: "Kako se izogibata dve jadrnici?", a: "Če imata jadrnici veter z različnih strani, se izogiba jadrnica, ki ima veter z leve strani. Če imata veter z iste strani, se izogiba privetrna jadrnica. Če jadrnica z vetrom z leve strani vidi drugo jadrnico privetrno in ne more zanesljivo ugotoviti, s katere strani ima druga jadrnica veter, se mora izogibati." },
  { cat: 5, q: "Pod kaj spada vodni skuter?", a: "Vodni skuter je osebno plovilo na motorni pogon oziroma posebno plovilo za šport in razvedrilo. Pri pravilih za izpit se obravnava ločeno, ker ima posebne omejitve plovbe in mora imeti upravljalec predpisano opremo, predvsem rešilni jopič." },
  { cat: 4, q: "Pri južni kardinalni oznaki po kateri strani oznake je varna voda?", a: "Pri južni kardinalni oznaki je varna oziroma najgloblja voda južno od oznake. Zato moramo pluti južno od oznake oziroma se nevarnosti izogniti po južni strani. Vrhnje znamenje južne kardinalne oznake sta dva črna stožca z vrhovoma navzdol." },
  { cat: 4, q: "Kako preberemo karakteristiko svetilnika, na primer B Bl (2) 5s 16m 6M?", a: "B pomeni bela luč. Bl (2) pomeni skupino dveh bliskov. 5s pomeni, da celoten cikel traja 5 sekund. 16m pomeni, da je luč 16 metrov nad morsko gladino. 6M pomeni, da je domet luči 6 navtičnih milj. Celoten opis pomeni: bela luč, dva bliska v skupini vsakih 5 sekund, višina luči 16 m, domet 6 M." },
  { cat: 4, q: "Kaj pomeni oznaka podvodni kabel na pomorski karti?", a: "Oznaka podvodni kabel pomeni, da je na morskem dnu položen kabel. Na tem območju ne sidramo, ne vlečemo sidra in ne izvajamo dejanj, ki bi lahko poškodovala kabel. Pri plovbi moramo biti na takšno oznako posebej pozorni predvsem pri sidranju." },
  { cat: 4, q: "Kako rešimo navigacijsko nalogo, če je iz svetilnika podan azimut 310° in razdalja 2 M?", a: "Na karti najprej poiščemo dani svetilnik. Iz svetilnika narišemo smer 310°, kar je smer proti severozahodu. Na tej smeri odmerimo 2 navtični milji, pri čemer razdaljo odmerimo na merilu geografske širine, ker 1 minuta širine pomeni 1 navtično miljo. Dobljena točka je položaj čolna; iz nje nato odčitamo geografsko širino oziroma druge zahtevane koordinate. Pomembno je razlikovati, ali je podan azimut iz svetilnika ali azimut svetilnika iz čolna; v drugem primeru bi uporabili nasprotni azimut." },,
  { cat: 6, q: "Kaj pomeni varna hitrost plovila?", a: "Varna hitrost je takšna hitrost, pri kateri lahko plovilo glede na okoliščine pravočasno in učinkovito ukrepa za preprečitev trčenja ter se lahko ustavi na primerni razdalji. Pri izbiri varne hitrosti upoštevamo vidljivost, gostoto prometa, manevrske lastnosti plovila, zaustavno pot, veter, morje, tok, bližino nevarnosti in razmerje med ugrezom plovila ter globino vode. Če uporabljamo radar, upoštevamo tudi njegove zmogljivosti in omejitve." },
  { cat: 6, q: "Kdaj se šteje, da plovilo prehiteva drugo plovilo?", a: "Plovilo prehiteva drugo plovilo, kadar se mu približuje iz smeri več kot 22,5° za prečnico, torej iz krmnega sektorja. Ponoči to pomeni, da vidi samo krmno luč prehitevanega plovila in ne vidi njegovih bočnih luči. Plovilo, ki prehiteva, se mora vedno izogibati prehitevanemu plovilu, dokler ga popolnoma ne prehiti in se od njega varno ne oddalji." },
  { cat: 6, q: "Katerim plovilom se mora umakniti plovilo na mehanski pogon, kadar plove?", a: "Plovilo na mehanski pogon, kadar plove, se mora umakniti plovilu, ki je nesposobno za manevriranje, plovilu z omejeno sposobnostjo manevriranja, plovilu, ki je zaposleno z ribolovom, in jadrnici. To ne velja, kadar je drugo plovilo samo dolžno izogibanja, na primer kadar prehiteva. V ozkih kanalih in drugih posebnih okoliščinah je treba dodatno upoštevati pravila za ožine, plovne poti in plovila, omejena s svojim ugrezom." },
  { cat: 6, q: "Katere so pozicijske luči plovil in v kakšnem kotu svetijo?", a: "Osnovne pozicijske luči so: jamborna luč, bočni luči in krmna luč. Bela jamborna luč sveti po premcu v loku 225°. Leva bočna luč je rdeča in sveti v loku 112,5°. Desna bočna luč je zelena in sveti v loku 112,5°. Bela krmna luč sveti v loku 135°. Luč za vleko je rumena in sveti v istem loku kot krmna luč, torej 135°. Krožna luč sveti v vseh smereh, torej 360°." },
  { cat: 6, q: "Kakšne luči morajo imeti različna plovila ponoči?", a: "Plovilo na mehanski pogon v plovbi ima belo jamborno luč, rdečo in zeleno bočno luč ter belo krmno luč; večja ladja ima lahko dve jamborni luči. Vlačilec ima poleg običajnih luči dodatne jamborne luči glede na dolžino vleka in rumeno krmno luč za vleko. Jadrnica v plovbi ima bočni luči in krmno luč, lahko tudi rdečo nad zeleno krožno lučjo na vrhu jambora. Plovilo na vesla mora kazati predpisane luči, če jih nima, pa mora imeti pripravljeno belo luč ali svetilko. Ribiška ladja ima krožni luči, pri vlečenju mreže zeleno nad belo, pri drugem ribolovu rdečo nad belo. Plovilo nesposobno za manevriranje kaže dve rdeči krožni luči. Plovilo z omejeno sposobnostjo manevriranja kaže rdečo, belo in rdečo krožno luč navpično. Plovilo omejeno s svojim ugrezom kaže tri rdeče krožne luči navpično. Pilotsko plovilo kaže belo nad rdečo krožno lučjo. Zasidrano plovilo kaže belo krožno luč, nasukano plovilo pa poleg sidrnih luči še dve rdeči krožni luči navpično." },
  { cat: 6, q: "Kakšni so osnovni zvočni signali za manevriranje, prehitevanje in zmanjšano vidljivost?", a: "En kratek pisk pomeni: zavijam desno. Dva kratka piska pomenita: zavijam levo. Trije kratki piski pomenijo: moji stroji delujejo nazaj. Pet kratkih piskov pomeni opozorilo oziroma dvom v namero drugega plovila. V ožini ali kanalu dva dolga in en kratek pisk pomenijo namero prehitevanja po desni, dva dolga in dva kratka piska pa namero prehitevanja po levi. Strinjanje s prehitevanjem pomeni zaporedje dolg-kratek-dolg-kratek. V zmanjšani vidljivosti ladja na mehanski pogon v plovbi daje en dolg zvok v presledkih največ 2 minuti; ladja na mehanski pogon, ki je na plovni poti in se ne premika, daje dva dolga zvoka." },
  { cat: 5, q: "Katere so predpisane minimalne oddaljenosti plovbe od obale za različna plovila?", a: "Motorni čoln, ki ne glisira, mora pluti najmanj 200 m od obale. Čoln, ki glisira, mora pluti najmanj 250 m od obale. Ladja mora pluti najmanj 300 m od obale. Vodni skuter sme pluti v pasu od 250 m do 2000 m od obale. Plovila na vesla in neregistrirana plovila, kot so kajak, vodno kolo, čoln na vesla in jadralec na deski, se smejo oddaljiti do 1000 m od obale. Od zunanjega roba označenega kopališča mora čoln pluti najmanj 50 m stran. Kopalci smejo plavati do označbe kopališča oziroma največ 150 m od obale, če kopališče ni označeno." },
  { cat: 5, q: "Kako se deli obalno morje?", a: "Obalno morje se deli na notranje morske vode in teritorialno morje. Notranje morske vode so vode med obalo in temeljno črto teritorialnega morja, kamor spadajo tudi zalivi in pristanišča. Teritorialno morje je morski pas navzven od temeljne črte, v katerem ima obalna država suverenost v skladu s pomorskimi predpisi." },
  { cat: 5, q: "Kaj je carinski pas na morju?", a: "Carinsko območje na morju obsega notranje morske vode in teritorialno morje. Po izpitnih vprašanjih obsega tudi pas 5 km v notranjost od obale. V tem območju veljajo carinski predpisi in nadzor pristojnih organov." },
  { cat: 5, q: "Kakšne so obveznosti voditelja čolna pri plovbi v tujih notranjih morskih vodah ali tujem teritorialnem morju?", a: "Pri plovbi v tuje notranje morske vode mora voditelj čolna upoštevati predpise obalne države, prijaviti prihod oziroma odhod na predpisanem mejnem prehodu in imeti zahtevane listine za čoln, posadko in potnike. Čoln za osebne namene mora v tujih notranjih morskih vodah praviloma izobesiti zastavo državne pripadnosti in zastavo države gostiteljice. Pri plovbi skozi tuje teritorialno morje velja pravica neškodljivega prehoda, kar pomeni, da mora plovilo pluti neprekinjeno, hitro in brez dejanj, ki bi ogrožala mir, red ali varnost obalne države." },
  { cat: 4, q: "Kje na pomorski karti odčitamo geografsko širino in kje geografsko dolžino?", a: "Geografsko širino odčitamo na levem ali desnem robu pomorske karte, kjer je merilo geografskih širin. Geografsko dolžino odčitamo na zgornjem ali spodnjem robu karte, kjer je merilo geografskih dolžin. Razdalje na karti merimo na merilu geografske širine, ker ena minuta geografske širine ustreza eni navtični milji." },
  { cat: 4, q: "Od kod se meri geografska širina in dolžina ter kakšne so največje vrednosti?", a: "Geografska širina se meri od ekvatorja proti severu ali jugu od 0° do 90° in se označuje z N ali S. Geografska dolžina se meri od začetnega oziroma Greenwichskega meridiana proti vzhodu ali zahodu od 0° do 180° in se označuje z E ali W. S širino in dolžino je določena vsaka točka na Zemlji oziroma položaj plovila na karti." },
  { cat: 4, q: "Kako na pomorski karti rišemo in čitamo kurz?", a: "Kurz na pomorski karti rišemo kot ravno kurzno linijo od izhodiščne točke proti cilju. S pomočjo navtičnih trikotnikov linijo prenesemo na kompasno rožo ali merilo smeri in odčitamo kot od severa v smeri urnega kazalca od 0° do 360°. Pri risanju kurza moramo paziti, ali uporabljamo pravi, magnetni ali kompasni kurz, in po potrebi upoštevati varijacijo in deviacijo." },
  { cat: 4, q: "Kaj so osnove zemeljskega magnetizma pri navigaciji?", a: "Zemlja deluje kot velik magnet, zato magnetna igla kompasa kaže proti magnetnemu severu, ne nujno proti pravemu geografskemu severu. Ker se pravi in magnetni meridiani ne pokrivajo, nastane varijacija. Na plovilu na kompas vplivajo tudi kovinski deli, električne naprave in drugo magnetno okolje plovila; zaradi tega nastane devijacija. Pri navigaciji moramo zato razlikovati pravi, magnetni in kompasni sever ter ustrezno popravljati kurze in azimute." },
  { cat: 4, q: "Kako preračunavamo kurze in azimute med pravimi, magnetnimi in kompasnimi vrednostmi?", a: "Pri preračunavanju uporabljamo varijacijo, deviacijo in skupni popravek. Skupni popravek je ps = varijacija + devijacija, pri čemer upoštevamo predznak E kot plus in W kot minus oziroma pravilo, ki ga uporablja učitelj. Iz pravega kurza dobimo kompasni kurz tako, da od pravega kurza odštejemo skupni popravek: Kk = Kp - ps. Iz kompasnega azimuta dobimo pravi azimut tako, da kompasnemu azimutu prištejemo skupni popravek: Ap = Ak + ps. Pri računanju rezultat po potrebi pretvorimo v območje od 0° do 360°." },
  { cat: 4, q: "Kako določimo oddaljenost na pomorski karti in prevoženo pot?", a: "Oddaljenost na pomorski karti merimo z navtičnim šestilom na merilu geografske širine ob levem ali desnem robu karte. Ena minuta geografske širine pomeni eno navtično miljo. Prevoženo pot lahko izračunamo iz hitrosti in časa po obrazcu pot = hitrost × čas, pri čemer je hitrost v vozlih, čas v urah, pot pa v navtičnih miljah." },
  { cat: 4, q: "Kako določimo položaj plovila z dvema azimutoma na isti objekt v časovnem razmaku?", a: "Najprej izmerimo prvi azimut na izbrani objekt in ga po potrebi pretvorimo v pravi azimut, nato ga vrišemo na karto. Po določenem času izmerimo drugi azimut na isti objekt, ga prav tako pretvorimo in vrišemo. Med meritvama ocenimo oziroma izračunamo prevoženo pot po kurzu in hitrosti ter prvo azimutno linijo prenesemo za prevoženo pot v smeri plovbe. Presečišče prenesene prve azimutne linije in druge azimutne linije predstavlja položaj plovila ob drugi meritvi." },
  { cat: 4, q: "Kako uporabljamo magnetni kompas pri plovbi?", a: "Magnetni kompas uporabljamo za držanje smeri plovbe in za merjenje kompasnih azimutov na objekte. Pri plovbi krmarimo tako, da čoln držimo na zahtevanem kompasnem kurzu. Pri navigaciji moramo vedeti, da kompas kaže kompasni oziroma magnetni sever, zato pri prenosu podatkov na karto upoštevamo deviacijo, varijacijo in skupni popravek. Kompas mora biti nameščen stran od predmetov in naprav, ki povzročajo magnetne motnje." },
  { cat: 3, q: "Kaj je magnetni vžig motorja?", a: "Magnetni vžig je sistem vžiga pri bencinskem motorju, pri katerem električni tok za iskro proizvaja magnet oziroma magnetni generator. Sistem za delovanje praviloma ne potrebuje akumulatorja, zato je pogost pri manjših izvenkrmnih motorjih. Njegova naloga je ustvariti dovolj visoko napetost, da na svečki preskoči iskra in vžge zmes goriva in zraka." },
  { cat: 3, q: "Kaj je baterijski vžig motorja?", a: "Baterijski vžig je sistem vžiga pri bencinskem motorju, pri katerem je vir električne energije akumulator. Preko vžigalne tuljave se nizka napetost akumulatorja pretvori v visoko napetost, ki na svečki povzroči preskok iskre. Sistem je odvisen od pravilnega stanja akumulatorja, električne napeljave, kontaktov oziroma elektronskega modula in vžigalnih svečk." },
  { cat: 3, q: "Kako je urejen dovod goriva pri bencinskem in dizelskem motorju?", a: "Pri bencinskem motorju gorivo iz rezervoarja preko cevi, filtra in črpalke pride do vplinjača ali naprave za vbrizg, kjer se pripravi zmes goriva in zraka. Pri dizelskem motorju gorivo iz rezervoarja preko filtrov in črpalke pride do visokotlačne črpalke oziroma sistema vbrizga, ki gorivo pod visokim tlakom vbrizga v valj. Pri dizelskem motorju je posebej pomembno, da v sistemu ni zraka ali vode, zato je treba sistem po potrebi odzračiti in redno čistiti oziroma menjati filtre." },
  { cat: 3, q: "Kakšna je razlika med dvotaktnim in štiritaktnim motorjem?", a: "Dvotaktni motor opravi delovni ciklus v dveh taktih oziroma v enem obratu ročične gredi. Štiritaktni motor opravi delovni ciklus v štirih taktih: sesanje, kompresija, delo oziroma ekspanzija in izpuh, kar pomeni dva obrata ročične gredi. Dvotaktni bencinski motor se običajno podmazuje z oljem v gorivni mešanici ali z ločenim doziranjem olja, štiritaktni motor pa ima tlačno mazanje z oljem iz oljnega korita." },
  { cat: 3, q: "Kaj je izvenkrmni motor?", a: "Izvenkrmni oziroma krmni motor je motor, ki je pritrjen na krmo čolna in je kot celota nameščen zunaj trupa. V enem sklopu ima motor, prenos, nogo in propeler. Prednosti so dobra dostopnost za servis, možnost snemanja, dobra manevrska sposobnost in možnost dviga noge oziroma propelerja v plitvi vodi. Slabosti so izpostavljenost zunanjim vplivom in vpliv teže na krmi na stabilnost čolna." },
  { cat: 3, q: "Kako pravilno vzdržujemo in rokujemo z motorjem?", a: "Motor uporabljamo po navodilih proizvajalca. Pred zagonom preverimo gorivo, olje, hlajenje, nevtralni položaj menjalnika in prezračevanje prostora motorja. Med delovanjem spremljamo zvok motorja, izpust hladilne vode, temperaturo, pritisk olja, polnjenje akumulatorja in opozorilne lučke. Po uporabi motor po potrebi speremo s sladko vodo, opravimo redne servise, menjamo olje, filtre, svečke, impeler in druge potrošne dele ter skrbimo, da je gorivo čisto in akumulator vzdrževan." },
  { cat: 3, q: "Kakšna maziva uporabljamo za motorje in zakaj so pomembna?", a: "Za motorje uporabljamo motorna olja, ki morajo ustrezati tipu motorja in navodilom proizvajalca. Pri štiritaktnih motorjih je olje v oljnem sistemu in omogoča tlačno mazanje. Pri dvotaktnih bencinskih motorjih je olje primešano gorivu ali pa ga posebna naprava dozira iz ločenega rezervoarja. Maziva zmanjšujejo trenje in obrabo, odvajajo toploto, pomagajo tesniti in varujejo dele motorja pred korozijo. Neustrezno mazanje lahko povzroči pregrevanje, povečano obrabo ali zaribanje motorja." },
  { cat: 2, q: "Za katera dna se uporabljajo posamezne vrste sider?", a: "Izbira sidra je odvisna od vrste morskega dna. Danforth sidro dobro drži v pesku in mulju. Plužno sidro je primerno za pesek, mulj in mešano dno. Admiralitetno sidro in sidro maček se lahko uporabljata na kamnitem ali skalnatem dnu, vendar se lahko zatakneta. Sidro goba je primerno predvsem za mehko muljasto dno in stalne priveze. Dežnik oziroma patentno sidro se uporablja predvsem pri manjših čolnih in lažjem sidranju. Ne glede na vrsto sidra je pomembno, da spustimo dovolj sidrne vrvi oziroma verige in preverimo, ali sidro drži." },
  { cat: 1, q: "Kako merimo temperaturo zraka?", a: "Temperaturo zraka merimo s termometrom. Izražamo jo v stopinjah Celzija. Pri meteorološkem opazovanju mora biti termometer v senci in zaščiten pred neposrednim soncem, ker bi sončno sevanje pokazalo previsoko temperaturo." },
  { cat: 1, q: "Kaj nam pove vlaga v zraku in kakšna je razlika med relativno in absolutno vlago?", a: "Vlaga pove, koliko vodne pare je v zraku. Absolutna vlaga je dejanska količina vodne pare v določeni količini zraka. Relativna vlaga pa pove, koliko odstotkov največje možne količine vodne pare pri določeni temperaturi zrak že vsebuje. Ko je relativna vlaga visoka in se zrak ohlaja, lažje nastanejo megla, oblaki ali padavine." },
  { cat: 1, q: "Kaj je zračni pritisk in kako ga merimo?", a: "Zračni pritisk je pritisk, ki ga zaradi svoje teže povzroča zrak. Merimo ga z barometrom, običajno v hektopaskalih oziroma milibarih. Spremembe zračnega pritiska so pomembne za vreme: padanje pritiska pogosto pomeni približevanje slabšega vremena, naraščanje pritiska pa izboljšanje ali stabilnejše vreme." },
  { cat: 1, q: "Kakšna je razlika med burjo in burinom?", a: "Burja je suh, hladen in sunkovit veter, ki piha predvsem iz severovzhoda proti morju. Lahko je zelo močna in nevarna ter ustvarja kratke, ostre valove. Burin je šibkejši priobalni nočni veter, ki nastane zaradi hitrejšega ohlajanja kopnega po sončnem zahodu in piha s kopnega proti morju, običajno iz smeri NNE do ENE. Burja je vremenski oziroma sinoptični veter, burin pa lokalni termični nočni veter." },
  { cat: 1, q: "Kakšna je razlika med jugom in širokom?", a: "V izpitnih vprašanjih se jugo in široko pogosto obravnavata skupaj kot topel in vlažen jugovzhodni veter. Jugo je udomačeno ime na Jadranu za veter iz smeri SE oziroma ESE do SSE, ki prinaša oblačno vreme, dež in valove. Široko oziroma sirocco je širši izraz za topel veter iz južnih oziroma jugovzhodnih smeri, ki prihaja iz Sredozemlja. V praksi sta na Jadranu izraza pogosto uporabljena kot zelo podobna ali skoraj sopomenki." },
  { cat: 1, q: "Kdaj se pojavljajo nenadne spremembe močnih vetrov?", a: "Nenadne spremembe močnih vetrov se pojavljajo predvsem ob nevihtah, prehodih hladnih front, prehodih ciklonov in pri lokalnih vremenskih pojavih ob obali. Na Jadranu so nevarne zlasti nenadne poletne vročinske nevihte, lokalna burja, nenadni obrati vetra ob prehodu ciklona ter lebič, ki lahko hitro doseže nevihtno moč. Ko opazimo znake poslabšanja, je treba pravočasno poiskati zavetje." },
  { cat: 1, q: "Kaj je anticiklonalno in kaj ciklonalno vreme?", a: "Anticiklonalno vreme je povezano z območjem visokega zračnega pritiska. Običajno je bolj stabilno, z manj oblačnosti in lepšim vremenom, lahko pa se ob obali vseeno pojavi burja. Ciklonalno vreme je povezano z območjem nizkega zračnega pritiska. Pogosto prinaša oblačnost, padavine, poslabšanje vremena in močnejše vetrove, na Jadranu na primer jugo, ciklonalno burjo ali lebič." },
  { cat: 1, q: "Kdaj se na severnem Jadranu pojavlja megla na morju?", a: "Megla na morju se pojavi, ko je zrak zelo vlažen in se ohladi do rosišča. Na severnem Jadranu je pogostejša v hladnejšem delu leta, zlasti jeseni in pozimi, ob mirnem vremenu, šibkem vetru in temperaturnih razlikah med morjem in zrakom. Lahko nastane tudi ob dotoku toplega vlažnega zraka nad hladnejšo morsko površino. V megli je treba zmanjšati hitrost, poostriti opazovanje in poslušanje ter uporabljati predpisane zvočne signale." },
  { cat: 1, q: "Kako nastanejo toplotne nevihte nad kopnim?", a: "Toplotne nevihte nastanejo, ko sonce močno segreje kopno in se topel, vlažen zrak začne hitro dvigati. Pri dviganju se zrak ohlaja, vodna para se kondenzira in nastanejo kopasti oblaki, ki se lahko razvijejo v kumulonimbus. Takšne nevihte spremljajo močni nalivi, grmenje, bliskanje in sunkovit veter. Na Jadranu se poleti lahko hitro razvijejo nad kopnim in se nato pomaknejo nad morje." }
];
